                     GREATEST(0, EXTRACT(EPOCH FROM (d.claim_deadline_at - NOW()))/86400)::int AS claim_days_left
              FROM detention_dwells d
              JOIN geofences g ON g.id=d.geofence_id AND g.company_id=d.company_id
