        var runsToday     = await db.ScalarLongAsync("SELECT COUNT(*) FROM report_runs WHERE tenant_id=@tenantId AND started_at::date=CURRENT_DATE", c => c.Parameters.AddWithValue("@tenantId", tenantId), ct: ct);
