        if (denied is not null) return denied;

        var row = await GetScopedUser(http, db, id, ct);
        return row is null
            ? Results.NotFound(ApiResponse<object>.Fail("User not found"))
            : Results.Ok(ApiResponse<object>.Ok(row, "User"));
    }

    internal static async Task<IResult> CreateAdminUser(HttpContext http, Dictionary<string, object?> body, Database db, AuditService audit, CancellationToken ct)
    {
        var denied = await RequireAdminPermission(http, audit, "users:create", "User", body, ct);
        if (denied is not null) return denied;

        var allUsers = await AllowAllUsers(http, db, ct);
        var currentCompanyId = GetCompanyId(http);
        var companyId = allUsers && long.TryParse(Get(body, "companyId")?.ToString(), out var requestedCompanyId) && requestedCompanyId > 0
            ? requestedCompanyId
            : currentCompanyId;
        var role = await ResolveRoleRecord(body, db, companyId, ct);
        // Get() returns DBNull (not null) for absent keys, which silently defeats
        // `?? default` and inserts NULL into NOT NULL columns (500 on the live API
        // whenever an optional field is omitted). Normalize DBNull away first.
        static object? Val(object? v) => v is null or DBNull ? null : v;
        var fullName = Val(Get(body, "fullName"))?.ToString()?.Trim() ?? Val(Get(body, "name"))?.ToString()?.Trim();
        var email = Val(Get(body, "email"))?.ToString()?.Trim().ToLowerInvariant();
        if (string.IsNullOrWhiteSpace(fullName) || string.IsNullOrWhiteSpace(email) || !System.Net.Mail.MailAddress.TryCreate(email, out _))
            return Results.BadRequest(ApiResponse<object>.Fail("Validation failed", ["A full name and valid email address are required."]));
        if (role is null)
            return Results.BadRequest(ApiResponse<object>.Fail("Validation failed", ["Select a role available to this tenant."]));
        var password = Val(Get(body, "password"))?.ToString();
        // Invite mode: no password means the user sets their own via a one-time
        // activation link (returned in the response). They stay Pending until the
        // link is used; password_hash stays NULL so login is impossible meanwhile.
        var inviteMode = string.IsNullOrWhiteSpace(password);
        var status = Val(Get(body, "status"))?.ToString()?.Trim() ?? (inviteMode ? "Pending" : "Active");
        if (!AllowedUserStatuses.Contains(status))
            return Results.BadRequest(ApiResponse<object>.Fail("Validation failed", ["Unsupported user status."]));
        var roleName = Val(role.GetValueOrDefault("name"))!;
        var permissionsJson = "[]";

        // Seat-limit quota (Platform Admin commercial control): block creation once the
        // tenant is at its subscribed seat count. No subscription row = no cap (legacy).
        var seatLimit = await db.ScalarLongAsync(
            "SELECT COALESCE((SELECT seat_limit FROM tenant_subscriptions WHERE company_id=@cid), 0)",
            c => c.Parameters.AddWithValue("@cid", companyId), ct);
        if (seatLimit > 0)
        {
            var seatCount = await db.ScalarLongAsync(
                $"SELECT COUNT(*) FROM users WHERE company_id=@cid AND {StaffSeatFilter}",
                c => c.Parameters.AddWithValue("@cid", companyId), ct);
            if (seatCount >= seatLimit)
                return Results.Json(ApiResponse<object>.Fail("Seat limit reached",
                    $"This organization is licensed for {seatLimit} seats and has {seatCount}. Increase the seat limit to add more users."),
                    statusCode: StatusCodes.Status409Conflict);
        }

        var id = await db.InsertAsync(
            @"INSERT INTO users (company_id, role_id, full_name, email, role_name, password_hash, permissions_json, status)
              VALUES (@companyId, @roleId, @fullName, @email, @roleName, @passwordHash, @permissionsJson::jsonb, @status)",
            c =>
            {
                c.Parameters.AddWithValue("@companyId", companyId);
                c.Parameters.AddWithValue("@roleId", role?.GetValueOrDefault("id") ?? DBNull.Value);
                c.Parameters.AddWithValue("@fullName", fullName);
                c.Parameters.AddWithValue("@email", email);
                c.Parameters.AddWithValue("@roleName", roleName);
                c.Parameters.AddWithValue("@passwordHash", inviteMode ? DBNull.Value : HashPassword(password!));
                c.Parameters.AddWithValue("@permissionsJson", permissionsJson);
                c.Parameters.AddWithValue("@status", status);
            }, ct);

        string? activationLink = null;
        DateTime? activationExpiresAt = null;
        if (inviteMode)
        {
            (activationLink, var linkExpiry) = await IssueActivationLinkAsync(http, db, id, companyId, email!, ct);
            activationExpiresAt = linkExpiry;
        }

        await audit.LogAsync(http, "user.created", "User", id,
            System.Text.Json.JsonSerializer.Serialize(new { email, role = roleName, invited = inviteMode }), ct);
        return Results.Created($"/api/admin/users/{id}",
            ApiResponse<object>.Ok(new { id, activationLink, activationExpiresAt },
                inviteMode ? "User invited — share the activation link" : "User created"));
    }

    private static async Task<IResult> UpdateAdminUser(HttpContext http, long id, Dictionary<string, object?> body, Database db, AuditService audit, CancellationToken ct)
    {
        var denied = await RequireAdminPermission(http, audit, "users:update", "User", new { id }, ct);
        if (denied is not null) return denied;

        var existing = await GetScopedUser(http, db, id, ct);
        if (existing is null) return Results.NotFound(ApiResponse<object>.Fail("User not found"));

        var role = await ResolveRoleRecord(body, db, Convert.ToInt64(existing["companyId"]), ct, existing);
        var currentCompanyId = GetCompanyId(http);
        var allUsers = await AllowAllUsers(http, db, ct);
        var companyId = allUsers && long.TryParse(Get(body, "companyId")?.ToString(), out var requestedCompanyId) && requestedCompanyId > 0
            ? requestedCompanyId
            : Convert.ToInt64(existing["companyId"]);

        var oldRoleName = existing["roleName"]?.ToString() ?? existing["roleDisplayName"]?.ToString() ?? existing["role_name"]?.ToString() ?? "";
        var newRoleName = role?.GetValueOrDefault("name")?.ToString() ?? Get(body, "roleName")?.ToString() ?? oldRoleName;
        var roleChanged = !string.Equals(oldRoleName, newRoleName, StringComparison.OrdinalIgnoreCase);
        var permissionsJson = "[]";

        var requestedStatus = Get(body, "status")?.ToString()?.Trim();
        if (!string.IsNullOrWhiteSpace(requestedStatus) && !AllowedUserStatuses.Contains(requestedStatus))
            return Results.BadRequest(ApiResponse<object>.Fail("Validation failed", ["Unsupported user status."]));

        await db.ExecuteAsync(
            @"UPDATE users
              SET company_id=@companyId,
                  role_id=@roleId,
                  full_name=COALESCE(NULLIF(@fullName,''), full_name),
                  email=COALESCE(NULLIF(@email,''), email),
                  role_name=@roleName,
                  permissions_json=@permissionsJson::jsonb,
                  status=COALESCE(NULLIF(@status,''), status)
              WHERE id=@id
              AND (@allUsers=1 OR company_id=@companyId)",
            c =>
            {
                c.Parameters.AddWithValue("@id", id);
                c.Parameters.AddWithValue("@companyId", companyId);
                c.Parameters.AddWithValue("@roleId", role?.GetValueOrDefault("id") ?? existing.GetValueOrDefault("roleId") ?? DBNull.Value);
                c.Parameters.AddWithValue("@fullName", Get(body, "fullName"));
                c.Parameters.AddWithValue("@email", Get(body, "email"));
                c.Parameters.AddWithValue("@roleName", newRoleName);
                c.Parameters.AddWithValue("@permissionsJson", permissionsJson);
                c.Parameters.AddWithValue("@status", Get(body, "status"));
                c.Parameters.AddWithValue("@allUsers", allUsers ? 1 : 0);
            }, ct);

        await audit.LogAsync(http, "user.updated", "User", id, System.Text.Json.JsonSerializer.Serialize(new { roleChanged, companyId }), ct);

        // Revoke the user's active sessions when their role/permissions change or they
        // are deactivated — otherwise the old (possibly higher) privileges keep working
        // via the in-flight token until it expires.
        var newStatus = Get(body, "status")?.ToString()?.Trim();
        var deactivated = !string.IsNullOrWhiteSpace(newStatus) &&
                          newStatus.ToLowerInvariant() is "disabled" or "inactive" or "suspended";
        if (roleChanged || deactivated)
        {
            await db.ExecuteAsync("DELETE FROM user_sessions WHERE user_id=@id", c => c.Parameters.AddWithValue("@id", id), ct);
            await audit.LogAsync(http, "user.role.changed", "User", id, System.Text.Json.JsonSerializer.Serialize(new { from = oldRoleName, to = newRoleName, sessionsRevoked = true }), ct);
        }
        return Results.Ok(ApiResponse<object>.Ok(new { id }, "User updated"));
    }

    private static async Task<IResult> DeleteAdminUser(HttpContext http, long id, Database db, AuditService audit, CancellationToken ct)
    {
        var denied = await RequireAdminPermission(http, audit, "users:delete", "User", new { id }, ct);
        if (denied is not null) return denied;

        var existing = await GetScopedUser(http, db, id, ct);
        if (existing is null) return Results.NotFound(ApiResponse<object>.Fail("User not found"));

        if (GetUserId(http) == id)
            return Results.Conflict(ApiResponse<object>.Fail("You cannot deactivate your own account."));

        var companyId = Convert.ToInt64(existing["companyId"]);
        var roleName = existing["roleName"]?.ToString() ?? string.Empty;
        if (roleName is "Tenant Admin" or "Company Admin" or "Super Admin")
        {
            var remainingAdmins = await db.ScalarLongAsync(
                @"SELECT COUNT(*) FROM users WHERE company_id=@companyId AND id<>@id
                  AND status='Active' AND role_name IN ('Tenant Admin','Company Admin','Super Admin')",
                c => { c.Parameters.AddWithValue("@companyId", companyId); c.Parameters.AddWithValue("@id", id); }, ct);
            if (remainingAdmins == 0)
                return Results.Conflict(ApiResponse<object>.Fail("Assign another active tenant administrator before deactivating this user."));
        }

        await db.ExecuteAsync("UPDATE users SET status='Inactive' WHERE id=@id AND company_id=@companyId", c => { c.Parameters.AddWithValue("@id", id); c.Parameters.AddWithValue("@companyId", companyId); }, ct);
        await db.ExecuteAsync("DELETE FROM user_sessions WHERE user_id=@id", c => c.Parameters.AddWithValue("@id", id), ct);
        await audit.LogAsync(http, "user.deactivated", "User", id, System.Text.Json.JsonSerializer.Serialize(new { status = "Inactive", sessionsRevoked = true }), ct);
        return Results.Ok(ApiResponse<object>.Ok(new { id }, "User deactivated"));
    }

    // Issues a one-time set-password link for a user (7-day expiry, token hashed at
    // rest via the password_reset_tokens table). This is the no-SMTP invite flow:
    // the admin copies the link and shares it through their own channel.
    private static async Task<(string link, DateTime expiresAt)> IssueActivationLinkAsync(
        HttpContext http, Database db, long userId, long companyId, string email, CancellationToken ct)
    {
        var rawToken = Convert.ToBase64String(RandomNumberGenerator.GetBytes(32))
            .TrimEnd('=').Replace('+', '-').Replace('/', '_');
        var tokenHash = Convert.ToHexString(SHA256.HashData(System.Text.Encoding.UTF8.GetBytes(rawToken)));
        var expiresAt = DateTime.UtcNow.AddDays(7);
        await db.ExecuteAsync(
            @"INSERT INTO password_reset_tokens (user_id, company_id, token_hash, expires_at, request_ip_hash)
              VALUES (@uid,@cid,@hash,NOW()+INTERVAL '7 days',@ip)
              ON CONFLICT (user_id) DO UPDATE SET token_hash=EXCLUDED.token_hash, expires_at=EXCLUDED.expires_at,
                consumed_at=NULL, request_ip_hash=EXCLUDED.request_ip_hash, created_at=NOW()",
            c =>
            {
                c.Parameters.AddWithValue("@uid", userId); c.Parameters.AddWithValue("@cid", companyId);
                c.Parameters.AddWithValue("@hash", tokenHash);
                c.Parameters.AddWithValue("@ip", HashRequestMetadata(http.Connection.RemoteIpAddress?.ToString()));
            }, ct);
        var link = $"{SsoWebBaseUrl()}/reset-password?email={Uri.EscapeDataString(email)}&token={Uri.EscapeDataString(rawToken)}&welcome=1";
        return (link, expiresAt);
    }

    private static async Task<IResult> AdminUserActivationLink(HttpContext http, long id, Database db, AuditService audit, CancellationToken ct)
    {
        var denied = await RequireAdminPermission(http, audit, "users:update", "User", new { id }, ct);
        if (denied is not null) return denied;

        var user = await GetScopedUser(http, db, id, ct);
        if (user is null) return Results.NotFound(ApiResponse<object>.Fail("User not found"));
        var status = user.GetValueOrDefault("status")?.ToString() ?? "";
        if (!string.Equals(status, "Active", StringComparison.OrdinalIgnoreCase) &&
            !string.Equals(status, "Pending", StringComparison.OrdinalIgnoreCase))
            return Results.Conflict(ApiResponse<object>.Fail("Activation links can only be issued for Active or Pending users."));

        var email = user.GetValueOrDefault("email")?.ToString() ?? "";
        var companyId = Convert.ToInt64(user["companyId"]);
        var (link, expiresAt) = await IssueActivationLinkAsync(http, db, id, companyId, email, ct);
        await audit.LogAsync(http, "user.activation_link.generated", "User", id,
            System.Text.Json.JsonSerializer.Serialize(new { expiresAt }), ct);
        return Results.Ok(ApiResponse<object>.Ok(new { link, expiresAt }, "Activation link generated"));
    }

    // ── Session management ────────────────────────────────────────────────────
    // The session token itself is never returned; the caller only sees metadata
    // plus an isCurrent flag computed server-side against the presenting token.

    private static async Task<IResult> MySessionsList(HttpContext http, Database db, CancellationToken ct)
    {
        var userId = GetUserId(http);
        if (userId <= 0) return Results.Unauthorized();
        var current = BearerToken(http);
        var rows = await db.QueryAsync(
            "SELECT id, session_token, created_at, expires_at FROM user_sessions WHERE user_id=@uid AND expires_at>NOW() ORDER BY created_at DESC",
            c => c.Parameters.AddWithValue("@uid", userId), ct);
        var sessions = rows.Select(r => new
        {
            id        = r.GetValueOrDefault("id"),
            createdAt = r.GetValueOrDefault("createdAt"),
            expiresAt = r.GetValueOrDefault("expiresAt"),
            isCurrent = string.Equals(r.GetValueOrDefault("sessionToken")?.ToString(), current, StringComparison.Ordinal),
        }).ToArray();
        return Results.Ok(ApiResponse<object>.Ok(sessions, "Active sessions"));
    }

    private static async Task<IResult> MySessionRevoke(HttpContext http, long id, Database db, AuditService audit, CancellationToken ct)
    {
        var userId = GetUserId(http);
        if (userId <= 0) return Results.Unauthorized();
        var removed = await db.ExecuteAsync(
            "DELETE FROM user_sessions WHERE id=@id AND user_id=@uid",
            c => { c.Parameters.AddWithValue("@id", id); c.Parameters.AddWithValue("@uid", userId); }, ct);
        if (removed == 0) return Results.NotFound(ApiResponse<object>.Fail("Session not found"));
        await audit.LogAsync(http, "session.revoked.self", "UserSession", id, ct: ct);
        return Results.Ok(ApiResponse<object>.Ok(new { id }, "Session revoked"));
    }

    private static async Task<IResult> AdminUserSessions(HttpContext http, long id, Database db, AuditService audit, CancellationToken ct)
    {
        var denied = RequirePermission(http, "users:view");
        if (denied is not null) return denied;
        var user = await GetScopedUser(http, db, id, ct);
        if (user is null) return Results.NotFound(ApiResponse<object>.Fail("User not found"));
        var rows = await db.QueryAsync(
            "SELECT id, created_at, expires_at FROM user_sessions WHERE user_id=@uid AND expires_at>NOW() ORDER BY created_at DESC",
            c => c.Parameters.AddWithValue("@uid", id), ct);
        return Results.Ok(ApiResponse<object>.Ok(rows, "User sessions"));
    }

    private static async Task<IResult> AdminUserSessionsRevoke(HttpContext http, long id, Database db, AuditService audit, CancellationToken ct)
    {
        var denied = await RequireAdminPermission(http, audit, "users:update", "User", new { id }, ct);
        if (denied is not null) return denied;
        var user = await GetScopedUser(http, db, id, ct);
        if (user is null) return Results.NotFound(ApiResponse<object>.Fail("User not found"));
        var removed = await db.ExecuteAsync(
            "DELETE FROM user_sessions WHERE user_id=@uid",
            c => c.Parameters.AddWithValue("@uid", id), ct);
        await audit.LogAsync(http, "session.revoked.admin", "User", id,
            System.Text.Json.JsonSerializer.Serialize(new { sessionsRevoked = removed }), ct);
        return Results.Ok(ApiResponse<object>.Ok(new { id, sessionsRevoked = removed }, "All sessions revoked"));
    }

    private static async Task<IResult> AdminRoles(HttpContext http, Database db, AuditService audit, CancellationToken ct)
    {
        var denied = RequirePermission(http, "roles:view");
        if (denied is not null) return denied;

        var companyId = GetCompanyId(http);
        var rows = await db.QueryAsync(
            @"SELECT r.id, r.name, r.permissions_json permissions_json, r.company_id company_id,
                     r.is_system is_system,
                     COUNT(u.id) FILTER (WHERE u.company_id=@companyId AND u.status='Active') user_count
              FROM roles r
              LEFT JOIN users u ON u.role_id=r.id
              WHERE r.company_id IS NULL OR r.company_id=@companyId
              GROUP BY r.id, r.name, r.permissions_json, r.company_id, r.is_system
              ORDER BY r.is_system DESC, r.name",
            c => c.Parameters.AddWithValue("@companyId", companyId), ct);
        return Results.Ok(ApiResponse<object>.Ok(rows, "Roles"));
    }

    private static IResult AdminPermissions(HttpContext http)
    {
        var denied = RequirePermission(http, "users:view");
        if (denied is not null) return denied;

        var permissions = RolePermissionDefaults
            .Values
            .SelectMany(static values => values)
            .Where(permission => !string.IsNullOrWhiteSpace(permission) && permission != "*")
            .Distinct(StringComparer.OrdinalIgnoreCase)
            .OrderBy(permission => permission, StringComparer.OrdinalIgnoreCase)
            .ToArray();

        return Results.Ok(ApiResponse<object>.Ok(permissions, "Permissions"));
    }

    // Self-service custom-role creation — lets an admin define a new role from the
    // available permission catalog (GET /api/admin/permissions), not just edit the
    // 16 built-ins. Gated on roles:create + audited.
    private static async Task<IResult> CreateAdminRole(HttpContext http, Dictionary<string, object?> body, Database db, AuditService audit, CancellationToken ct)
    {
        var denied = await RequireAdminPermission(http, audit, "roles:create", "Role", body, ct);
        if (denied is not null) return denied;

        var name = Get(body, "name")?.ToString()?.Trim();
        if (string.IsNullOrWhiteSpace(name))
            return Results.BadRequest(ApiResponse<object>.Fail("Validation failed", ["Role name is required."]));

        var companyId = GetCompanyId(http);
        var clash = await db.ScalarLongAsync("SELECT COUNT(*) FROM roles WHERE company_id=@companyId AND LOWER(name)=LOWER(@name)",
            c => { c.Parameters.AddWithValue("@companyId", companyId); c.Parameters.AddWithValue("@name", name); }, ct);
        if (clash > 0)
            return Results.Conflict(ApiResponse<object>.Fail("Role already exists", [$"A role named '{name}' already exists."]));

        var permissionKeys = ExtractPermissions(Get(body, "permissions") ?? Get(body, "permissionsJson"));
        if (ValidateRolePermissions(http, permissionKeys) is { } permissionError) return permissionError;
        var permissions = System.Text.Json.JsonSerializer.Serialize(permissionKeys);
        var id = await db.InsertAsync(
            "INSERT INTO roles (company_id, name, permissions_json, is_system) VALUES (@companyId, @name, @permissions::jsonb, FALSE)",
            c => { c.Parameters.AddWithValue("@companyId", companyId); c.Parameters.AddWithValue("@name", name); c.Parameters.AddWithValue("@permissions", permissions); }, ct);
        // Mirror into role_permissions so the normalized store (permission-coverage
        // KPI, future joins) never lags permissions_json — UpdateAdminRole already
        // dual-writes; creation must too.
        foreach (var permission in permissionKeys)
        {
            await db.ExecuteAsync(
                "INSERT INTO role_permissions (role_id, permission_key) VALUES (@id, @permission) ON CONFLICT (role_id, permission_key) DO NOTHING",
                c =>
                {
                    c.Parameters.AddWithValue("@id", id);
                    c.Parameters.AddWithValue("@permission", permission);
                }, ct);
        }
        await audit.LogAsync(http, "role.created", "Role", id,
            System.Text.Json.JsonSerializer.Serialize(new { name, permissionCount = permissionKeys.Count }), ct: ct);
        return Results.Created($"/api/admin/roles/{id}", ApiResponse<object>.Ok(new { id, name, permissions = permissionKeys }, "Role created"));
    }

    private static async Task<IResult> UpdateAdminRole(HttpContext http, long id, Dictionary<string, object?> body, Database db, AuditService audit, CancellationToken ct)
    {
        var denied = await RequireAdminPermission(http, audit, "roles:update", "Role", new { id }, ct);
        if (denied is not null) return denied;

        var companyId = GetCompanyId(http);
        var existing = await db.QuerySingleAsync(
            "SELECT * FROM roles WHERE id=@id AND company_id=@companyId AND is_system=FALSE LIMIT 1",
            c => { c.Parameters.AddWithValue("@id", id); c.Parameters.AddWithValue("@companyId", companyId); }, ct);
        if (existing is null) return Results.NotFound(ApiResponse<object>.Fail("Role not found"));

        var permissionsProvided = (body.ContainsKey("permissions") && Get(body, "permissions") is not (null or DBNull))
            || (body.ContainsKey("permissionsJson") && Get(body, "permissionsJson") is not (null or DBNull));
        var permissionKeys = ExtractPermissions(permissionsProvided
            ? (Get(body, "permissions") is not (null or DBNull) ? Get(body, "permissions") : Get(body, "permissionsJson"))
            : existing.GetValueOrDefault("permissionsJson"));
        if (ValidateRolePermissions(http, permissionKeys) is { } permissionError) return permissionError;
        var permissions = System.Text.Json.JsonSerializer.Serialize(permissionKeys);
        var name = Get(body, "name") ?? existing.GetValueOrDefault("name")?.ToString() ?? "Role";
        await db.ExecuteAsync(
            "UPDATE roles SET name=COALESCE(NULLIF(@name,''), name), permissions_json=@permissions::jsonb WHERE id=@id",
            c =>
            {
                c.Parameters.AddWithValue("@id", id);
                c.Parameters.AddWithValue("@name", name);
                c.Parameters.AddWithValue("@permissions", permissions);
            }, ct);
        await db.ExecuteAsync("DELETE FROM role_permissions WHERE role_id=@id", c => c.Parameters.AddWithValue("@id", id), ct);
        foreach (var permission in permissionKeys)
        {
            await db.ExecuteAsync(
                "INSERT INTO role_permissions (role_id, permission_key) VALUES (@id, @permission)",
                c =>
                {
                    c.Parameters.AddWithValue("@id", id);
                    c.Parameters.AddWithValue("@permission", permission);
                }, ct);
        }

        await db.ExecuteAsync(
            "DELETE FROM user_sessions WHERE user_id IN (SELECT id FROM users WHERE company_id=@companyId AND role_id=@roleId)",
            c => { c.Parameters.AddWithValue("@companyId", companyId); c.Parameters.AddWithValue("@roleId", id); }, ct);

        await audit.LogAsync(http, "role.updated", "Role", id, System.Text.Json.JsonSerializer.Serialize(new { permissions, sessionsRevoked = true }), ct);
        return Results.Ok(ApiResponse<object>.Ok(new { id }, "Role updated"));
    }

    private static async Task<IResult> CreateAdminAuditEvent(HttpContext http, Dictionary<string, object?> body, Database db, AuditService audit, CancellationToken ct)
    {
        var denied = RequirePermission(http, "audit:view");
        if (denied is not null) return denied;

        var action = Get(body, "actionName")?.ToString() ?? "admin.action";
        var entity = Get(body, "entityName")?.ToString() ?? "Admin";
        var entityId = long.TryParse(Get(body, "entityId")?.ToString(), out var parsedId) ? parsedId : (long?)null;
        var details = Get(body, "detailsJson")?.ToString();
        await audit.LogAsync(http, action, entity, entityId, details, ct);
        return Results.Ok(ApiResponse<object>.Ok(new { ok = true }, "Audit event logged"));
    }

    private static async Task<IResult?> RequireAdminPermission(HttpContext http, AuditService audit, string permission, string entity, object? details, CancellationToken ct)
    {
        var denied = RequirePermission(http, permission);
        if (denied is not null)
        {
            await audit.LogAsync(http, "permission.denied", entity, null, System.Text.Json.JsonSerializer.Serialize(new { permission, details }), ct);
        }
        return denied;
    }

    private static async Task<bool> AllowAllUsers(HttpContext http, Database db, CancellationToken ct)
    {
        // Tenant administration is deliberately tenant-only. Cross-tenant operations
        // belong to /api/platform and its separate platform identity/session model.
        await Task.CompletedTask;
        return false;
    }

    private static bool IsSuperAdmin(HttpContext http)
    {
        if (http.Items.TryGetValue(AuthRoleItemKey, out var roleRaw) && roleRaw is not null)
        {
            var role = roleRaw.ToString() ?? string.Empty;
            if (role.Equals("Super Admin", StringComparison.OrdinalIgnoreCase) || role.Equals("platform_super_admin", StringComparison.OrdinalIgnoreCase))
            {
                return true;
            }
        }

        if (http.Items.TryGetValue(AuthPermissionsItemKey, out var permsRaw) && permsRaw is string[] perms)
        {
            return perms.Any(permission => string.Equals(permission, "*", StringComparison.OrdinalIgnoreCase));
        }

        return false;
    }

    private static async Task<bool> PlatformTenantExists(Database db, CancellationToken ct)
    {
        var count = await db.ScalarLongAsync(
            "SELECT COUNT(*) FROM companies WHERE LOWER(company_code) IN ('opx-platform','opstrax-platform','platform') OR LOWER(name) LIKE '%platform%'",
            ct: ct);
        return count > 0;
    }

    private static async Task<Dictionary<string, object?>?> ResolveRoleRecord(Dictionary<string, object?> body, Database db, long companyId, CancellationToken ct, Dictionary<string, object?>? existing = null)
    {
        var roleId = long.TryParse(Get(body, "roleId")?.ToString(), out var parsedRoleId) ? parsedRoleId : 0;
        var roleName = Get(body, "roleName")?.ToString();

        if (roleId > 0)
        {
            return await db.QuerySingleAsync("SELECT id, name, permissions_json permissionsJson FROM roles WHERE id=@id AND (company_id IS NULL OR company_id=@companyId) LIMIT 1", c => { c.Parameters.AddWithValue("@id", roleId); c.Parameters.AddWithValue("@companyId", companyId); }, ct);
        }

        if (!string.IsNullOrWhiteSpace(roleName))
        {
            return await db.QuerySingleAsync("SELECT id, name, permissions_json permissionsJson FROM roles WHERE name=@name AND (company_id IS NULL OR company_id=@companyId) ORDER BY company_id NULLS LAST LIMIT 1", c => { c.Parameters.AddWithValue("@name", roleName); c.Parameters.AddWithValue("@companyId", companyId); }, ct);
        }

        if (existing is not null && existing.TryGetValue("roleId", out var existingRoleId) && existingRoleId is not null && existingRoleId is not DBNull)
        {
            var existingId = Convert.ToInt64(existingRoleId);
            return await db.QuerySingleAsync("SELECT id, name, permissions_json permissionsJson FROM roles WHERE id=@id AND (company_id IS NULL OR company_id=@companyId) LIMIT 1", c => { c.Parameters.AddWithValue("@id", existingId); c.Parameters.AddWithValue("@companyId", companyId); }, ct);
        }

        return null;
    }

    private static async Task<Dictionary<string, object?>?> GetScopedUser(HttpContext http, Database db, long id, CancellationToken ct)
    {
        var allowAll = await AllowAllUsers(http, db, ct);
        var companyId = GetCompanyId(http);
        return await db.QuerySingleAsync(
            @"SELECT u.id, u.company_id companyId, c.company_code, c.name companyName, u.role_id roleId, u.role_name roleName, u.full_name fullName, u.email, u.status,
                     u.branch_id branchId, u.customer_id customerId, u.created_at createdAt, COALESCE(r.name, u.role_name) roleDisplayName,
                     (SELECT MAX(s.created_at) FROM user_sessions s WHERE s.user_id=u.id) lastLoginAt,
                     CASE WHEN COALESCE(m.mfa_enabled,FALSE) THEN 'Enabled' ELSE 'Not enrolled' END mfaStatus
              FROM users u
              JOIN companies c ON c.id=u.company_id
              LEFT JOIN roles r ON r.id=u.role_id
              LEFT JOIN user_mfa_status m ON m.user_id=u.id
              WHERE u.id=@id AND (@allUsers=1 OR u.company_id=@companyId)
              LIMIT 1",
            c =>
            {
                c.Parameters.AddWithValue("@id", id);
                c.Parameters.AddWithValue("@companyId", companyId);
                c.Parameters.AddWithValue("@allUsers", allowAll ? 1 : 0);
            }, ct);
    }

    private static IResult? ValidateRolePermissions(HttpContext http, List<string> requested)
    {
        var catalog = RolePermissionDefaults.Values
            .SelectMany(static values => values)
            .Where(static value => !string.IsNullOrWhiteSpace(value) && value != "*")
            .ToHashSet(StringComparer.OrdinalIgnoreCase);

        if (requested.Any(permission => permission == "*" || !catalog.Contains(permission)))
            return Results.BadRequest(ApiResponse<object>.Fail("Validation failed", ["The role contains an unknown or protected permission."]));

        if (!IsSuperAdmin(http) && http.Items.TryGetValue(AuthPermissionsItemKey, out var raw) && raw is string[] actorPermissions)
        {
            var actor = actorPermissions.ToHashSet(StringComparer.OrdinalIgnoreCase);
            var beyondGrantBoundary = requested.Where(permission => !actor.Contains(permission)).ToArray();
            if (beyondGrantBoundary.Length > 0)
                return Results.Json(ApiResponse<object>.Fail("Grant boundary exceeded", ["You cannot grant permissions that you do not hold."]), statusCode: StatusCodes.Status403Forbidden);
        }

        return null;
    }

    private static List<string> ExtractPermissions(object? raw)
    {
        if (raw is null || raw is DBNull) return [];
        if (raw is string str)
        {
            try
            {
                var parsed = System.Text.Json.JsonSerializer.Deserialize<List<string>>(str);
                return parsed?.Where(permission => !string.IsNullOrWhiteSpace(permission)).Select(permission => permission.Trim()).Distinct(StringComparer.OrdinalIgnoreCase).ToList() ?? [];
            }
            catch
            {
                return str.Split(',', StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries).ToList();
            }
        }

        if (raw is IEnumerable<object> items)
        {
            return items.Select(item => item?.ToString()?.Trim())
                .Where(permission => !string.IsNullOrWhiteSpace(permission))
                .Distinct(StringComparer.OrdinalIgnoreCase)
                .Cast<string>()
                .ToList();
        }

        return [];
    }

    // ── Proof of Delivery ──────────────────────────────────────────────────────

    private static async Task<IResult> CaptureProof(HttpContext http, long id, Dictionary<string, object?> body, Database db, AuditService audit, CancellationToken ct)
    {
        var companyId = GetCompanyId(http);
        var receivedBy = Get(body, "receivedBy")?.ToString() ?? "Unknown";
        var notes = Get(body, "notes")?.ToString() ?? "";
        var signatureUrl = Get(body, "signatureDataUrl")?.ToString() ?? "";
        var proofType = string.IsNullOrEmpty(signatureUrl) ? "Verbal Confirmation" : "Digital Signature";
        // All proof writes run inside a single transaction with SELECT FOR UPDATE so
        // concurrent captures of the same job are serialised at the DB level and a
        // mid-flight failure rolls back instead of leaving orphaned Superseded rows.
        var proofId = await db.WithTransactionAsync(async (conn, tx) =>
        {
            await using var selectCmd = new Npgsql.NpgsqlCommand(
                @"SELECT id FROM proof_of_delivery
                  WHERE company_id=@companyId AND job_id=@id AND status='Pending'
                  ORDER BY created_at DESC, id DESC
                  LIMIT 1
                  FOR UPDATE", conn, tx);
            selectCmd.Parameters.AddWithValue("@companyId", companyId);
            selectCmd.Parameters.AddWithValue("@id", id);
            var pendingId = await selectCmd.ExecuteScalarAsync(ct);

            long pid;
            if (pendingId is not null and not DBNull)
            {
                pid = Convert.ToInt64(pendingId);

                await using var supersedeCmd = new Npgsql.NpgsqlCommand(
                    @"UPDATE proof_of_delivery
                      SET status='Superseded',
                          notes=CASE
                              WHEN COALESCE(notes,'') = '' THEN 'Superseded by captured proof.'
                              ELSE notes || ' | Superseded by captured proof.'
                          END
                      WHERE company_id=@companyId AND job_id=@id AND status='Pending' AND id<>@proofId",
                    conn, tx);
                supersedeCmd.Parameters.AddWithValue("@companyId", companyId);
                supersedeCmd.Parameters.AddWithValue("@id", id);
                supersedeCmd.Parameters.AddWithValue("@proofId", pid);
                await supersedeCmd.ExecuteNonQueryAsync(ct);

                await using var captureCmd = new Npgsql.NpgsqlCommand(
                    @"UPDATE proof_of_delivery
                      SET receiver_name=@receiver,
                          received_by=@receiver,
                          proof_type=@proofType,
                          signature_url=@sigUrl,
                          status='Captured',
                          notes=@notes,
                          captured_at=NOW()
                      WHERE id=@proofId AND company_id=@companyId",
                    conn, tx);
                captureCmd.Parameters.AddWithValue("@proofId", pid);
                captureCmd.Parameters.AddWithValue("@companyId", companyId);
                captureCmd.Parameters.AddWithValue("@receiver", receivedBy);
                captureCmd.Parameters.AddWithValue("@proofType", proofType);
                captureCmd.Parameters.AddWithValue("@sigUrl", signatureUrl);
                captureCmd.Parameters.AddWithValue("@notes", notes);
                await captureCmd.ExecuteNonQueryAsync(ct);
            }
            else
            {
                await using var insertCmd = new Npgsql.NpgsqlCommand(
                    @"INSERT INTO proof_of_delivery (company_id, job_id, receiver_name, received_by, proof_type, signature_url, status, notes, captured_at)
                      VALUES (@companyId, @id, @receiver, @receiver, @proofType, @sigUrl, 'Captured', @notes, NOW())
                      RETURNING id",
                    conn, tx);
                insertCmd.Parameters.AddWithValue("@companyId", companyId);
                insertCmd.Parameters.AddWithValue("@id", id);
                insertCmd.Parameters.AddWithValue("@receiver", receivedBy);
                insertCmd.Parameters.AddWithValue("@proofType", proofType);
                insertCmd.Parameters.AddWithValue("@sigUrl", signatureUrl);
                insertCmd.Parameters.AddWithValue("@notes", notes);
                var inserted = await insertCmd.ExecuteScalarAsync(ct);
                pid = inserted is null or DBNull ? 0 : Convert.ToInt64(inserted);
            }

            await using var jobCmd = new Npgsql.NpgsqlCommand(
                "UPDATE jobs SET proof_status='Captured', status='Delivered' WHERE id=@id AND company_id=@companyId",
                conn, tx);
            jobCmd.Parameters.AddWithValue("@id", id);
            jobCmd.Parameters.AddWithValue("@companyId", companyId);
            await jobCmd.ExecuteNonQueryAsync(ct);

            return pid;
        }, ct);
        await audit.LogAsync(http, "proof.captured", "Job", id, ct: ct);
        await AddTimeline(db, GetCompanyId(http), "Job", id, "proof.captured", $"POD captured — {receivedBy}", ct);
        return Results.Ok(ApiResponse<object>.Ok(new { id, proofId, status = "Captured", proofType, receivedBy }, "Proof of delivery captured"));
    }

    private static async Task<IResult> ProofOfDeliveryList(HttpContext http, Database db, CancellationToken ct)
    {
        var companyId = GetCompanyId(http);
        var rows = await db.QueryAsync(
            @"WITH latest_pod AS (
                  SELECT DISTINCT ON (pod.job_id)
                         pod.id,
                         pod.company_id,
                         pod.job_id,
                         pod.receiver_name,
                         pod.received_by,
                         pod.proof_type,
                         pod.photo_url,
                         pod.signature_url,
                         pod.status,
                         pod.notes,
                         pod.captured_at,
                         pod.created_at
                  FROM proof_of_delivery pod
                  WHERE pod.company_id=@cid
                  ORDER BY pod.job_id, COALESCE(pod.captured_at, pod.created_at) DESC, pod.id DESC
              )
              SELECT lp.id,
                     j.id job_id,
                     COALESCE(j.job_number, j.job_code) job_number,
                     j.status job_status,
                     j.proof_status,
                     j.sla_status,
                     j.customer_update_status,
                     j.tracking_code,
                     j.pickup_address,
                     j.dropoff_address,
                     j.eta,
                     c.name customer_name,
                     v.vehicle_code,
                     d.full_name driver_name,
                     lp.id proof_id,
                     COALESCE(lp.status, CASE WHEN j.proof_status='Pending' THEN 'Pending' ELSE 'Awaiting Capture' END) status,
                     -- 'Placeholder' is an internal not-yet-captured marker; never surface it in the UI.
                     CASE WHEN COALESCE(lp.proof_type, 'Placeholder') = 'Placeholder' THEN 'Awaiting Capture' ELSE lp.proof_type END proof_type,
                     lp.receiver_name,
                     lp.received_by,
                     lp.photo_url,
                     lp.signature_url,
                     lp.notes,
                     lp.captured_at,
                     lp.created_at
              FROM jobs j
              LEFT JOIN latest_pod lp ON lp.job_id=j.id
              LEFT JOIN customers c ON c.id=j.customer_id
              LEFT JOIN vehicles v ON v.id=j.assigned_vehicle_id
              LEFT JOIN drivers d ON d.id=j.assigned_driver_id
              WHERE j.company_id=@cid
                AND j.deleted_at IS NULL
                AND (j.proof_status='Pending' OR lp.id IS NOT NULL OR j.status IN ('Completed','Delivered','At Stop'))
              ORDER BY CASE WHEN COALESCE(lp.status, CASE WHEN j.proof_status='Pending' THEN 'Pending' ELSE 'Awaiting Capture' END)='Pending' THEN 0 ELSE 1 END,
                       COALESCE(lp.captured_at, j.eta, j.scheduled_end, j.scheduled_start) DESC
              LIMIT 150",
            c => c.Parameters.AddWithValue("@cid", companyId), ct);
        return Results.Ok(ApiResponse<object>.Ok(rows, "Proof of delivery records"));
    }

    private static async Task<IResult> ProofOfDeliverySummary(HttpContext http, Database db, CancellationToken ct)
    {
        var companyId = GetCompanyId(http);
        var row = await db.QuerySingleAsync(
            @"WITH latest_pod AS (
                  SELECT DISTINCT ON (pod.job_id)
                         pod.job_id,
                         pod.status,
                         pod.proof_type
                  FROM proof_of_delivery pod
                  WHERE pod.company_id=@cid
                  ORDER BY pod.job_id, COALESCE(pod.captured_at, pod.created_at) DESC, pod.id DESC
              ),
              proof_surface AS (
                  SELECT j.id job_id,
                         COALESCE(lp.status, CASE WHEN j.proof_status='Pending' THEN 'Pending' ELSE 'Awaiting Capture' END) surface_status,
                         CASE WHEN COALESCE(lp.proof_type, 'Placeholder') = 'Placeholder' THEN 'Awaiting Capture' ELSE lp.proof_type END surface_proof_type,
                         j.proof_status
                  FROM jobs j
                  LEFT JOIN latest_pod lp ON lp.job_id=j.id
                  WHERE j.company_id=@cid
                    AND j.deleted_at IS NULL
                    AND (j.proof_status='Pending' OR lp.job_id IS NOT NULL OR j.status IN ('Completed','Delivered','At Stop'))
              )
              SELECT COUNT(*) total,
                     SUM(CASE WHEN surface_status='Captured' THEN 1 ELSE 0 END) captured,
                     SUM(CASE WHEN surface_status='Pending' THEN 1 ELSE 0 END) pending,
                     SUM(CASE WHEN surface_proof_type='Digital Signature' THEN 1 ELSE 0 END) digital_signatures,
                     SUM(CASE WHEN proof_status='Pending' THEN 1 ELSE 0 END) jobs_pending_proof
              FROM proof_surface",
            c => c.Parameters.AddWithValue("@cid", companyId), ct);
        return Results.Ok(ApiResponse<object>.Ok(row ?? new Dictionary<string, object?>(), "POD summary"));
    }

    // ── Alerts / Exception Management ──────────────────────────────────────────

    private const string AlertsSql =
        @"SELECT ai.id,
                 ai.title,
                 ai.body,
                 ai.severity,
                 ai.status,
                 ai.category,
                 ai.alert_type alertType,
                 ai.entity_type entityType,
                 ai.entity_id entityId,
                 ai.acknowledged_at acknowledgedAt,
                 ai.closed_at closedAt,
                 COALESCE(ack.full_name, ai.acknowledged_by) acknowledgedBy,
                 ai.recommended_action recommendedAction,
                 ai.created_at createdAt,
                 ai.company_id companyId,
                 CASE
                   WHEN ai.entity_type IN ('vehicle','Vehicle') THEN (SELECT v.vehicle_code FROM vehicles v WHERE v.id = ai.entity_id AND v.company_id = ai.company_id LIMIT 1)
                   WHEN ai.entity_type IN ('driver','Driver') THEN (SELECT d.full_name FROM drivers d WHERE d.id = ai.entity_id AND d.company_id = ai.company_id LIMIT 1)
                   WHEN ai.entity_type IN ('job','shipment','Job','Shipment') THEN (SELECT COALESCE(j.job_number, j.job_code) FROM jobs j WHERE j.id = ai.entity_id AND j.company_id = ai.company_id LIMIT 1)
                   WHEN ai.entity_type IN ('customer','Customer') THEN (SELECT c.name FROM customers c WHERE c.id = ai.entity_id AND c.company_id = ai.company_id LIMIT 1)
                   ELSE NULL
                 END entity,
                 CASE
                   WHEN ai.entity_type IN ('vehicle','Vehicle') THEN '/vehicles/roster'
                   WHEN ai.entity_type IN ('driver','Driver') THEN '/drivers/roster'
                   WHEN ai.entity_type IN ('job','shipment','Job','Shipment') THEN '/jobs'
                   WHEN ai.entity_type IN ('customer','Customer') THEN '/customers'
                   WHEN ai.category = 'Maintenance' THEN '/maintenance'
                   WHEN ai.category = 'Compliance' THEN '/compliance'
                   WHEN ai.category = 'Safety' THEN '/safety'
                   WHEN ai.category = 'Telematics' THEN '/iot-devices'
                   ELSE '/alerts'
                 END entityRoute,
                 CASE
                   WHEN ai.created_at >= NOW() - INTERVAL '1 hour' THEN CONCAT(GREATEST(1, FLOOR(EXTRACT(EPOCH FROM (NOW() - ai.created_at)) / 60))::INT, 'm')
                   WHEN ai.created_at >= NOW() - INTERVAL '24 hours' THEN CONCAT(GREATEST(1, FLOOR(EXTRACT(EPOCH FROM (NOW() - ai.created_at)) / 3600))::INT, 'h')
                   ELSE CONCAT(GREATEST(1, FLOOR(EXTRACT(EPOCH FROM (NOW() - ai.created_at)) / 86400))::INT, 'd')
                 END age
          FROM ai_insights ai
          LEFT JOIN users ack
            ON CAST(ack.id AS TEXT) = ai.acknowledged_by
           AND ack.company_id = ai.company_id";

    private static async Task<IResult> AlertsSummary(HttpContext http, Database db, CancellationToken ct)
    {
        var denied = RequirePermission(http, "alerts:view");
        if (denied is not null) return denied;
        var companyId = GetCompanyId(http);
        var total       = await db.ScalarLongAsync("SELECT COUNT(*) FROM ai_insights WHERE company_id=@cid", c => c.Parameters.AddWithValue("@cid", companyId), ct);
        var critical    = await db.ScalarLongAsync("SELECT COUNT(*) FROM ai_insights WHERE severity='Critical' AND company_id=@cid", c => c.Parameters.AddWithValue("@cid", companyId), ct);
        var high        = await db.ScalarLongAsync("SELECT COUNT(*) FROM ai_insights WHERE severity='High' AND company_id=@cid", c => c.Parameters.AddWithValue("@cid", companyId), ct);
        var open        = await db.ScalarLongAsync("SELECT COUNT(*) FROM ai_insights WHERE status='Open' AND company_id=@cid", c => c.Parameters.AddWithValue("@cid", companyId), ct);
        var acked       = await db.ScalarLongAsync("SELECT COUNT(*) FROM ai_insights WHERE status='Acknowledged' AND company_id=@cid", c => c.Parameters.AddWithValue("@cid", companyId), ct);
        var closed      = await db.ScalarLongAsync("SELECT COUNT(*) FROM ai_insights WHERE status='Closed' AND company_id=@cid", c => c.Parameters.AddWithValue("@cid", companyId), ct);
        return Results.Ok(ApiResponse<object>.Ok(new { total, critical, high, open, acknowledged = acked, closed }, "Alert summary"));
    }

    private static async Task<IResult> AlertsList(HttpContext http, Database db, CancellationToken ct)
    {
        var companyId = GetCompanyId(http);
        var denied = RequirePermission(http, "alerts:view");
        if (denied is not null) return denied;
        var rows = await db.QueryAsync(
            AlertsSql + " WHERE ai.company_id=@cid ORDER BY ARRAY_POSITION(ARRAY['Critical','High','Warning','Info'], ai.severity), ai.created_at DESC",
            c => c.Parameters.AddWithValue("@cid", companyId), ct);
        return Results.Ok(ApiResponse<object>.Ok(rows, "Alerts"));
    }

    private static async Task<IResult> AlertDetail(HttpContext http, long id, Database db, CancellationToken ct)
    {
        var companyId = GetCompanyId(http);
        var denied = RequirePermission(http, "alerts:view");
        if (denied is not null) return denied;
        var row = await db.QuerySingleAsync(AlertsSql + " WHERE ai.id=@id AND ai.company_id=@cid LIMIT 1",
            c => { c.Parameters.AddWithValue("@id", id); c.Parameters.AddWithValue("@cid", companyId); }, ct);
        if (row is null) return Results.NotFound();

        var tasks = await db.QueryAsync(
            @"SELECT
                aft.id,
                aft.alert_id AS alert_id,
                aft.title,
                aft.description,
                aft.priority,
                aft.status,
                aft.owner_name,
                aft.due_at,
                aft.closed_at,
                aft.created_at,
                aft.updated_at,
                u.full_name AS assigned_to_name
              FROM alert_follow_up_tasks aft
              LEFT JOIN users u ON u.id = aft.assigned_to_user_id
              WHERE aft.alert_id=@id
                AND aft.company_id=@cid
                AND aft.deleted_at IS NULL
              ORDER BY aft.created_at DESC",
            c =>
            {
                c.Parameters.AddWithValue("@id", id);
                c.Parameters.AddWithValue("@cid", companyId);
            }, ct);

        var auditTrail = await AuditTrail(db, "Alert", id, ct);
        return Results.Ok(ApiResponse<object>.Ok(new { alert = row, tasks, auditTrail }, "Alert detail"));
    }

    private static async Task<IResult> AlertAcknowledge(HttpContext http, long id, Dictionary<string, object?> body, Database db, AuditService audit, CancellationToken ct)
    {
        var denied = RequirePermission(http, "alerts:acknowledge");
        if (denied is not null) return denied;
        var companyId = GetCompanyId(http);
        var note = Get(body, "note")?.ToString() ?? "";
        var userId = http.Items.TryGetValue(AuthUserIdItemKey, out var uid) ? uid?.ToString() ?? "" : "";
        await db.ExecuteAsync(
            "UPDATE ai_insights SET status='Acknowledged', acknowledged_at=NOW(), acknowledged_by=@by WHERE id=@id AND company_id=@cid",
            c => { c.Parameters.AddWithValue("@id", id); c.Parameters.AddWithValue("@cid", companyId); c.Parameters.AddWithValue("@by", userId); }, ct);
        await audit.LogAsync(http, "alert.acknowledged", "Alert", id, JsonSerializer.Serialize(new { note }), ct);
        return Results.Ok(ApiResponse<object>.Ok(new { id, status = "Acknowledged", note }, "Alert acknowledged"));
    }

    private static async Task<IResult> AlertClose(HttpContext http, long id, Dictionary<string, object?> body, Database db, AuditService audit, CancellationToken ct)
    {
        var denied = RequirePermission(http, "alerts:close");
        if (denied is not null) return denied;
        var companyId = GetCompanyId(http);
        var resolution = Get(body, "resolution")?.ToString() ?? "";
        await db.ExecuteAsync(
            "UPDATE ai_insights SET status='Closed', closed_at=NOW() WHERE id=@id AND company_id=@cid",
            c => { c.Parameters.AddWithValue("@id", id); c.Parameters.AddWithValue("@cid", companyId); }, ct);
        await audit.LogAsync(http, "alert.closed", "Alert", id, JsonSerializer.Serialize(new { resolution }), ct);
        return Results.Ok(ApiResponse<object>.Ok(new { id, status = "Closed", resolution }, "Alert closed"));
    }

    private static async Task<IResult> AlertCreateTask(HttpContext http, long id, Dictionary<string, object?> body, Database db, AuditService audit, CancellationToken ct)
    {
        var denied = RequirePermission(http, "alerts:acknowledge");
        if (denied is not null) return denied;
        var companyId = GetCompanyId(http);
        var alert = await db.QuerySingleAsync(
            "SELECT id, title FROM ai_insights WHERE id=@id AND company_id=@cid LIMIT 1",
            c =>
            {
                c.Parameters.AddWithValue("@id", id);
                c.Parameters.AddWithValue("@cid", companyId);
            }, ct);
        if (alert is null) return Results.NotFound(ApiResponse<object>.Fail("Alert not found"));

        var title = Get(body, "title")?.ToString() ?? "Follow-up task";
        var description = Get(body, "description")?.ToString() ?? $"Created from alert #{id}";
        var ownerName = Get(body, "owner")?.ToString() ?? "";
        var userId = http.Items.TryGetValue(AuthUserIdItemKey, out var uid) && uid is not null ? Convert.ToInt64(uid) : 0L;
        var taskId = await db.InsertAsync(
            @"INSERT INTO alert_follow_up_tasks (
                company_id, alert_id, title, description, priority, status,
                assigned_to_user_id, created_by_user_id, owner_name, due_at, created_at, updated_at
              )
              VALUES (
                @cid, @alertId, @title, @desc, COALESCE(@priority, 'High'), 'Open',
                @assignedTo, @createdBy, NULLIF(@ownerName, ''), @dueAt, NOW(), NOW()
              )",
            c =>
            {
                c.Parameters.AddWithValue("@cid", companyId);
                c.Parameters.AddWithValue("@alertId", id);
                c.Parameters.AddWithValue("@title", title);
                c.Parameters.AddWithValue("@desc", description);
                c.Parameters.AddWithValue("@priority", Get(body, "priority")?.ToString() ?? "High");
                c.Parameters.AddWithValue("@assignedTo", Get(body, "assignedToUserId") ?? DBNull.Value);
                c.Parameters.AddWithValue("@createdBy", userId > 0 ? userId : DBNull.Value);
                c.Parameters.AddWithValue("@ownerName", ownerName);
                c.Parameters.AddWithValue("@dueAt", Get(body, "dueAt") ?? DBNull.Value);
            }, ct);
        await audit.LogAsync(http, "alert.task.created", "Alert", id, JsonSerializer.Serialize(new { taskId, title }), ct);
        return Results.Ok(ApiResponse<object>.Ok(new { taskId, alertId = id, status = "Created", title }, "Task created"));
    }

    private static Task<IResult> AlertRulesList(HttpContext http, Database db, CancellationToken ct)
    {
        var denied = RequirePermission(http, "alerts:view");
        if (denied is not null) return Task.FromResult(denied);

        return OkRows(db,
            @"SELECT
                id,
                COALESCE(rule_key, 'ALR-' || id::TEXT) AS ""ruleKey"",
                COALESCE(NULLIF(rule_name, ''), 'Alert rule') AS name,
                COALESCE(NULLIF(category, ''), NULLIF(module_name, ''), 'Operations') AS category,
                COALESCE(threshold_text, '') AS threshold,
                COALESCE(action_type, 'Create operational alert') AS action,
                COALESCE(channels, 'In-App') AS channels,
                COALESCE(priority, 'Medium') AS priority,
                COALESCE(recipients, '') AS recipients,
                COALESCE(status, 'Active') AS status,
                COALESCE(triggered_today, 0) AS ""triggeredToday"",
                last_triggered_at AS ""lastTriggered"",
                updated_at AS ""updatedAt"",
                created_at AS ""createdAt""
              FROM alert_rules
              WHERE COALESCE(company_id, tenant_id, 1) = @cid
                AND deleted_at IS NULL
              ORDER BY category, name",
            c => c.Parameters.AddWithValue("@cid", GetCompanyId(http)), ct: ct);
    }

