    private static async Task<IResult> AboutHealthSummary(IHostEnvironment env, Database db, CancellationToken ct)
    {
        long moduleCount;
        string dbStatus;
        try
        {
            moduleCount = await db.ScalarLongAsync("SELECT COUNT(DISTINCT table_name) FROM information_schema.tables WHERE table_schema=current_schema()", ct: ct);
            dbStatus    = "Connected";
        }
        catch
        {
            moduleCount = 0;
            dbStatus    = "Degraded";
        }

        var asm = System.Reflection.Assembly.GetExecutingAssembly().GetName().Version;
        return Results.Ok(ApiResponse<object>.Ok(new
        {
            // apiStatus is truthful by construction — this API produced the response.
            apiStatus        = "Connected",
            databaseStatus   = dbStatus,
            // The Node side service has no health probe wired here; say so rather
            // than fabricate a "Connected" claim.
            nodeEventsStatus = "Not monitored",
            moduleCount      = moduleCount > 0 ? $"{moduleCount} tables" : "—",
            version          = asm is null ? "Enterprise" : $"Enterprise {asm.Major}.{asm.Minor}.{asm.Build}",
            environment      = env.EnvironmentName
        }, "Health summary"));
    }

    // ── Telemetry observability counters ─────────────────────────────────────────
    private static long _telemetryAccepted;
    private static long _telemetryRejected;
    private static long _telemetryAuthFailed;
    private static long _telemetryRejectedReplay;
    private static long _telemetryRejectedValidation;
    private static long _activeSseClients;
    private static long _alertsGenerated;

    // ── Telemetry DTOs ──────────────────────────────────────────────────────────
    // VehicleCode/TenantId/CompanyId/VehicleId/DriverId are intentionally absent —
    // all binding comes from the authenticated device record, not the request body.
    private sealed record TelemetryPingBody(
        decimal Lat, decimal Lng,
        decimal SpeedMph = 0, int Heading = 0,
        string EventType = "ping",
        string? EngineStatus = null, decimal? FuelLevel = null,
        decimal? OdometerMiles = null, decimal? BatteryVoltage = null,
        decimal? AccuracyMeters = null,
        string? EventTime = null,
        string? SourceChannel = null,
        string? ClientGeneratedId = null,
        string? CorrelationId = null,
        string? CausationId = null
    );

    private sealed record DeviceProvisionBody(
        string DeviceSerial, string? DeviceModel = null, string? Provider = null,
        long? VehicleId = null, long? DriverId = null,
        string? FirmwareVersion = null, string? Notes = null,
        // Hardware GPS-tracker IMEI (GT06/Concox/PT40-class). Optional — ELD units that
        // authenticate by device_serial + HMAC leave it null. When present it is the key the
        // trusted gateway resolves the device by, so it is globally unique (ux_eld_devices_imei).
        string? Imei = null
    );

    private sealed record DeviceAssignBody(long? VehicleId, long? DriverId);

    private sealed record TelemetryRuleBody(
        decimal ThresholdValue, string? Severity = null,
        bool Enabled = true, string? Notes = null
    );

    // ── Stream-ticket helpers (key sourced from TelemetryKeyStore for cross-module access) ─
    private static string IssueStreamTicket(long userId, long companyId)
        => TelemetryTicketHelper.Issue(TelemetryKeyStore.SseTicketKey, userId, companyId);

    // ── POST /api/telemetry/stream-ticket ────────────────────────────────────────
    // Session-authenticated; issues a 90-second HMAC-SHA256 scoped ticket for SSE.
    private static IResult TelemetryStreamTicket(HttpContext http)
    {
        var userId    = Convert.ToInt64(http.Items[AuthUserIdItemKey] ?? 0L);
        var companyId = GetCompanyId(http);
        var ticket    = IssueStreamTicket(userId, companyId);
        var expiresAt = DateTimeOffset.UtcNow.AddSeconds(90);
        return Results.Ok(ApiResponse<object>.Ok(new { ticket, expiresAt, ttlSeconds = 90 }, "Stream ticket issued"));
    }

    // ── POST /api/telemetry/ingest ───────────────────────────────────────────────
    // Device-authenticated via X-Device-Key + HMAC-SHA256 payload signature.
    // Required headers: X-Device-Key, X-Timestamp, X-Nonce, X-Signature
    // All company/vehicle/driver binding comes from the device record — never from body.
    private static async Task<IResult> TelemetryIngest(HttpContext http, Database db, AuditService audit, TelemetryLiveStateService telemetry, PostgresAiFoundationService ai, CancellationToken ct)
    {
        // 1. Buffer body so we can read raw bytes for HMAC, then deserialize
        http.Request.EnableBuffering();
        string rawBody;
        using (var reader = new System.IO.StreamReader(http.Request.Body, System.Text.Encoding.UTF8, leaveOpen: true))
            rawBody = await reader.ReadToEndAsync(ct);
        http.Request.Body.Position = 0;

        TelemetryPingBody? body;
        try
        {
            body = System.Text.Json.JsonSerializer.Deserialize<TelemetryPingBody>(rawBody,
                new System.Text.Json.JsonSerializerOptions { PropertyNameCaseInsensitive = true });
        }
        catch
        {
            System.Threading.Interlocked.Increment(ref _telemetryRejectedValidation);
            System.Threading.Interlocked.Increment(ref _telemetryRejected);
            return Results.BadRequest(ApiResponse<object>.Fail("Invalid JSON body"));
        }
        if (body is null)
        {
            System.Threading.Interlocked.Increment(ref _telemetryRejectedValidation);
            System.Threading.Interlocked.Increment(ref _telemetryRejected);
            return Results.BadRequest(ApiResponse<object>.Fail("Missing request body"));
        }

        // 2. Extract auth headers
        var rawKey     = http.Request.Headers["X-Device-Key"].FirstOrDefault()?.Trim();
        var xTimestamp = http.Request.Headers["X-Timestamp"].FirstOrDefault()?.Trim();
        var xNonce     = http.Request.Headers["X-Nonce"].FirstOrDefault()?.Trim();
        var xSig       = http.Request.Headers["X-Signature"].FirstOrDefault()?.Trim();

        if (string.IsNullOrWhiteSpace(rawKey))
        {
            System.Threading.Interlocked.Increment(ref _telemetryAuthFailed);
            System.Threading.Interlocked.Increment(ref _telemetryRejected);
            return Results.Json(ApiResponse<object>.Fail("Missing X-Device-Key"), statusCode: 401);
        }
        if (string.IsNullOrWhiteSpace(xTimestamp) || string.IsNullOrWhiteSpace(xNonce))
        {
            System.Threading.Interlocked.Increment(ref _telemetryAuthFailed);
            System.Threading.Interlocked.Increment(ref _telemetryRejected);
            return Results.Json(ApiResponse<object>.Fail("Missing X-Timestamp or X-Nonce"), statusCode: 401);
        }
        if (string.IsNullOrWhiteSpace(xSig))
        {
            System.Threading.Interlocked.Increment(ref _telemetryAuthFailed);
            System.Threading.Interlocked.Increment(ref _telemetryRejected);
            return Results.Json(ApiResponse<object>.Fail("Missing X-Signature"), statusCode: 401);
        }

        // 3. X-Timestamp freshness — ±60 s (tighter window for HMAC; prevents clock-skew abuse)
        if (!long.TryParse(xTimestamp, out var tsUnix) ||
            Math.Abs(DateTimeOffset.UtcNow.ToUnixTimeSeconds() - tsUnix) > 60)
        {
            System.Threading.Interlocked.Increment(ref _telemetryRejectedReplay);
            System.Threading.Interlocked.Increment(ref _telemetryRejected);
            return Results.Json(ApiResponse<object>.Fail("X-Timestamp outside 60-second window"), statusCode: 422);
        }

        // 4. Nonce length guard
        if (xNonce.Length > 128)
        {
            System.Threading.Interlocked.Increment(ref _telemetryRejected);
            return Results.Json(ApiResponse<object>.Fail("X-Nonce too long"), statusCode: 422);
        }

        // 5. Look up device — binding all authority from the record, not from the request body
        var device = await db.QuerySingleAsync(
            @"SELECT e.id, e.company_id, e.vehicle_id, e.driver_id, e.status, e.device_serial, e.hmac_secret
              FROM eld_devices e
              WHERE e.api_key_hash = encode(sha256(@rawKey::bytea), 'hex') AND e.deleted_at IS NULL
              LIMIT 1",
            c => c.Parameters.AddWithValue("@rawKey", rawKey), ct);

        if (device is null)
        {
            System.Threading.Interlocked.Increment(ref _telemetryAuthFailed);
            System.Threading.Interlocked.Increment(ref _telemetryRejected);
            return Results.Json(ApiResponse<object>.Fail("Device not recognized"), statusCode: 401);
        }

        // 6. Reject non-Active (revoked, suspended) devices
        if (!string.Equals(device["status"]?.ToString(), "Active", StringComparison.OrdinalIgnoreCase))
        {
            System.Threading.Interlocked.Increment(ref _telemetryRejected);
            return Results.Json(ApiResponse<object>.Fail("Device is not active"), statusCode: 403);
        }

        var deviceId   = Convert.ToInt64(device["id"]);
        var hmacSecret = device["hmacSecret"]?.ToString();

        // 7. HMAC-SHA256 payload signature verification (constant-time)
        //    Canonical: "{METHOD}\n{path}\n{X-Timestamp}\n{X-Nonce}\n{sha256-hex(body)}"
        if (string.IsNullOrWhiteSpace(hmacSecret))
        {
            System.Threading.Interlocked.Increment(ref _telemetryAuthFailed);
            System.Threading.Interlocked.Increment(ref _telemetryRejected);
            return Results.Json(ApiResponse<object>.Fail("Device credentials are incomplete"), statusCode: 401);
        }

        var bodyHex  = TelemetryHmacHelper.Sha256Hex(rawBody);
        var expected = TelemetryHmacHelper.ComputeSignature(
            System.Text.Encoding.UTF8.GetBytes(hmacSecret),
            http.Request.Method.ToUpperInvariant(),
            http.Request.Path.Value ?? "/api/telemetry/ingest",
            xTimestamp, xNonce, bodyHex);
        if (!TelemetryHmacHelper.ConstantTimeEquals(expected, xSig))
        {
            System.Threading.Interlocked.Increment(ref _telemetryAuthFailed);
            System.Threading.Interlocked.Increment(ref _telemetryRejected);
            return Results.Json(ApiResponse<object>.Fail("Signature mismatch"), statusCode: 401);
        }

        // 8. Nonce replay — atomic INSERT; duplicate nonce for same device → DB unique key violation
        try
        {
            await db.ExecuteAsync(
                "INSERT INTO telemetry_nonces (device_id, nonce) VALUES (@did, @nonce)",
                c => { c.Parameters.AddWithValue("@did", deviceId); c.Parameters.AddWithValue("@nonce", xNonce); }, ct);
        }
        catch (Npgsql.PostgresException ex) when (ex.SqlState == "23505")
        {
            System.Threading.Interlocked.Increment(ref _telemetryRejectedReplay);
            System.Threading.Interlocked.Increment(ref _telemetryRejected);
            return Results.Json(ApiResponse<object>.Fail("Duplicate nonce — replay detected"), statusCode: 409);
        }

        // 9. Secondary body EventTime check — GPS event time ±300 s
        if (!TelemetryTicketHelper.IsTimestampFresh(body.EventTime))
        {
            System.Threading.Interlocked.Increment(ref _telemetryRejectedReplay);
            System.Threading.Interlocked.Increment(ref _telemetryRejected);
            return Results.Json(ApiResponse<object>.Fail("EventTime outside acceptable window"), statusCode: 422);
        }

        // 10. Coordinate and speed validation
        if (!TelemetryTicketHelper.IsCoordinateValid(body.Lat, body.Lng))
        {
            System.Threading.Interlocked.Increment(ref _telemetryRejectedValidation);
            System.Threading.Interlocked.Increment(ref _telemetryRejected);
            return Results.Json(ApiResponse<object>.Fail("lat/lng invalid or null island"), statusCode: 422);
        }
        if (!TelemetryTicketHelper.IsSpeedValid(body.SpeedMph))
        {
            System.Threading.Interlocked.Increment(ref _telemetryRejectedValidation);
            System.Threading.Interlocked.Increment(ref _telemetryRejected);
            return Results.Json(ApiResponse<object>.Fail("Speed out of range"), statusCode: 422);
        }

        // 11. All binding from device record — body cannot override company/vehicle/driver
        var companyId = device["companyId"] is { } cv && cv is not DBNull ? Convert.ToInt64(cv) : 1L;
        var vehicleId = device["vehicleId"] is { } vv && vv is not DBNull ? (long?)Convert.ToInt64(vv) : null;
        var driverId  = device["driverId"]  is { } dv && dv is not DBNull ? (long?)Convert.ToInt64(dv) : null;

        // 12. Fetch tenant-configurable speed threshold (default 65 mph)
        var speedThreshold = await db.ScalarDecimalAsync(
            "SELECT threshold_value FROM telemetry_rules WHERE company_id=@cid AND rule_type='speeding' AND enabled=TRUE LIMIT 1",
            c => c.Parameters.AddWithValue("@cid", companyId), ct) ?? 65m;

        // 13. Insert into location_events
        var eventId = await db.InsertAsync(
            @"INSERT INTO location_events
                (company_id, vehicle_id, device_id, driver_id, lat, lng, speed_mph, heading,
                 accuracy_meters, event_type, engine_status, fuel_level, odometer_miles,
                 battery_voltage, nonce, source, source_channel, correlation_id, causation_id,
                 client_generated_id, idempotency_key, event_time, received_at)
              VALUES
                (@companyId, @vehicleId, @deviceId, @driverId, @lat, @lng, @speedMph, @heading,
                 @acc, @eventType, @eng, @fuel, @odo, @batt, @nonce, 'device', @sourceChannel,
                 @correlationId, @causationId, @clientGeneratedId, @idempotencyKey, NOW(), NOW())",
            c =>
            {
                c.Parameters.AddWithValue("@companyId", companyId);
                c.Parameters.AddWithValue("@vehicleId", vehicleId ?? (object)DBNull.Value);
                c.Parameters.AddWithValue("@deviceId",  deviceId);
                c.Parameters.AddWithValue("@driverId",  driverId  ?? (object)DBNull.Value);
                c.Parameters.AddWithValue("@lat",        body.Lat);
                c.Parameters.AddWithValue("@lng",        body.Lng);
                c.Parameters.AddWithValue("@speedMph",   body.SpeedMph);
                c.Parameters.AddWithValue("@heading",    body.Heading);
                c.Parameters.AddWithValue("@acc",        body.AccuracyMeters ?? (object)DBNull.Value);
                c.Parameters.AddWithValue("@eventType",  body.EventType);
                c.Parameters.AddWithValue("@eng",        body.EngineStatus ?? "Running");
                c.Parameters.AddWithValue("@fuel",       body.FuelLevel    ?? (object)DBNull.Value);
                c.Parameters.AddWithValue("@odo",        body.OdometerMiles ?? (object)DBNull.Value);
                c.Parameters.AddWithValue("@batt",       body.BatteryVoltage ?? (object)DBNull.Value);
                c.Parameters.AddWithValue("@nonce",      xNonce);
                c.Parameters.AddWithValue("@sourceChannel", body.SourceChannel ?? "device");
                c.Parameters.AddWithValue("@correlationId", body.CorrelationId ?? (object)DBNull.Value);
                c.Parameters.AddWithValue("@causationId",   body.CausationId ?? (object)DBNull.Value);
                c.Parameters.AddWithValue("@clientGeneratedId", body.ClientGeneratedId ?? (object)DBNull.Value);
                c.Parameters.AddWithValue("@idempotencyKey", body.ClientGeneratedId ?? (object)DBNull.Value);
            }, ct);

        // 14. Upsert latest_vehicle_positions (one row per company+vehicle, O(1) via UNIQUE KEY)
        if (vehicleId.HasValue)
        {
            // Additive provenance: native ELD HMAC ingest. Stamp source/device_fix_time/
            // normalized_at ONLY when the columns exist (deploy-safe — production may
            // pre-date migration 001). device_fix_time is the device-asserted GPS time
            // (body.EventTime, already validated fresh); normalized_at is our ingest time.
            var hasProv = await TelemetryProvenance.ColumnsAvailableAsync(db, ct);
            object deviceFixTime = DBNull.Value;
            if (hasProv && DateTimeOffset.TryParse(body.EventTime, CultureInfo.InvariantCulture,
                    DateTimeStyles.AssumeUniversal | DateTimeStyles.AdjustToUniversal, out var dft))
                deviceFixTime = dft.UtcDateTime;
            var provCols = hasProv ? ", source, device_fix_time, normalized_at" : "";
            var provVals = hasProv ? $", '{TelemetryProvenance.SourceNativeEld}', @deviceFixTime, NOW()" : "";
            var provUpd  = hasProv
                ? $", source='{TelemetryProvenance.SourceNativeEld}', device_fix_time=EXCLUDED.device_fix_time, normalized_at=NOW()"
                : "";

            await db.ExecuteAsync(
                $@"INSERT INTO latest_vehicle_positions
                    (company_id, vehicle_id, device_id, driver_id, lat, lng, speed_mph, heading,
                     accuracy_meters, engine_status, fuel_level, odometer_miles, battery_voltage,
                     event_time, received_at, event_count, source_event_id, correlation_id,
                     causation_id, source_channel, telemetry_status, risk_level, alert_count,
                     open_alert_count, next_action, summary_json, updated_at{provCols})
                  VALUES
                    (@companyId, @vehicleId, @deviceId, @driverId, @lat, @lng, @speedMph, @heading,
                     @acc, @eng, @fuel, @odo, @batt, NOW(), NOW(), 1, @sourceEventId, @correlationId,
                     @causationId, @sourceChannel, @telemetryStatus, @riskLevel, @alertCount,
                     @openAlertCount, @nextAction, @summaryJson::jsonb, NOW(){provVals})
                  ON CONFLICT (company_id, vehicle_id) DO UPDATE SET
                    device_id=EXCLUDED.device_id, driver_id=EXCLUDED.driver_id,
                    lat=EXCLUDED.lat, lng=EXCLUDED.lng, speed_mph=EXCLUDED.speed_mph,
                    heading=EXCLUDED.heading, accuracy_meters=EXCLUDED.accuracy_meters,
                    engine_status=EXCLUDED.engine_status, fuel_level=EXCLUDED.fuel_level,
                    odometer_miles=EXCLUDED.odometer_miles, battery_voltage=EXCLUDED.battery_voltage,
                    event_time=EXCLUDED.event_time, received_at=EXCLUDED.received_at, event_count=latest_vehicle_positions.event_count+1,
                    source_event_id=EXCLUDED.source_event_id, correlation_id=EXCLUDED.correlation_id,
                    causation_id=EXCLUDED.causation_id, source_channel=EXCLUDED.source_channel,
                    telemetry_status=EXCLUDED.telemetry_status, risk_level=EXCLUDED.risk_level,
                    alert_count=EXCLUDED.alert_count, open_alert_count=EXCLUDED.open_alert_count,
                    next_action=EXCLUDED.next_action, summary_json=EXCLUDED.summary_json, updated_at=NOW(){provUpd}
                  WHERE latest_vehicle_positions.event_time IS NULL OR latest_vehicle_positions.event_time <= EXCLUDED.event_time",
                c =>
                {
                    c.Parameters.AddWithValue("@companyId", companyId);
                    c.Parameters.AddWithValue("@vehicleId", vehicleId.Value);
                    c.Parameters.AddWithValue("@deviceId",  deviceId);
                    c.Parameters.AddWithValue("@driverId",  driverId ?? (object)DBNull.Value);
                    c.Parameters.AddWithValue("@lat",   body.Lat);
                    c.Parameters.AddWithValue("@lng",   body.Lng);
                    c.Parameters.AddWithValue("@speedMph", body.SpeedMph);
                    c.Parameters.AddWithValue("@heading",  body.Heading);
                    c.Parameters.AddWithValue("@acc",  body.AccuracyMeters ?? (object)DBNull.Value);
                    c.Parameters.AddWithValue("@eng",  body.EngineStatus ?? "Running");
                    c.Parameters.AddWithValue("@fuel", body.FuelLevel ?? (object)DBNull.Value);
                    c.Parameters.AddWithValue("@odo",  body.OdometerMiles ?? (object)DBNull.Value);
                    c.Parameters.AddWithValue("@batt", body.BatteryVoltage ?? (object)DBNull.Value);
                    c.Parameters.AddWithValue("@sourceEventId", eventId);
                    c.Parameters.AddWithValue("@correlationId", body.CorrelationId ?? (object)DBNull.Value);
                    c.Parameters.AddWithValue("@causationId", body.CausationId ?? (object)DBNull.Value);
                    c.Parameters.AddWithValue("@sourceChannel", body.SourceChannel ?? "device");
                    c.Parameters.AddWithValue("@telemetryStatus", "healthy");
                    c.Parameters.AddWithValue("@riskLevel", "low");
                    c.Parameters.AddWithValue("@alertCount", 0);
                    c.Parameters.AddWithValue("@openAlertCount", 0);
                    c.Parameters.AddWithValue("@nextAction", "No action required");
                    c.Parameters.AddWithValue("@summaryJson", JsonSerializer.Serialize(new { vehicleId, companyId, status = "healthy" }));
                    if (hasProv) c.Parameters.AddWithValue("@deviceFixTime", deviceFixTime);
                }, ct);
        }

        // 15. Heartbeat
        await db.ExecuteAsync(
            "UPDATE eld_devices SET last_seen_at=NOW() WHERE id=@id",
            c => c.Parameters.AddWithValue("@id", deviceId), ct);

        // 16. Alert: speeding (ingest-time, uses tenant threshold, no duplicate open alert)
        if (vehicleId.HasValue && body.SpeedMph > speedThreshold)
        {
            var openSpd = await db.ScalarLongAsync(
                "SELECT COUNT(*) FROM telemetry_alerts WHERE company_id=@cid AND vehicle_id=@vid AND alert_type='speeding' AND status='Open'",
                c => { c.Parameters.AddWithValue("@cid", companyId); c.Parameters.AddWithValue("@vid", vehicleId.Value); }, ct);
            if (openSpd == 0)
            {
                var alertId = await db.InsertAsync(
                    @"INSERT INTO telemetry_alerts (company_id, vehicle_id, device_id, driver_id, alert_type, severity, message, source_event_id, status)
                      VALUES (@cid, @vid, @did, @drid, 'speeding',
                              COALESCE((SELECT severity FROM telemetry_rules WHERE company_id=@cid AND rule_type='speeding' AND enabled=TRUE LIMIT 1), 'High'),
                              @msg, @eid, 'Open')
                      RETURNING id",
                    c =>
                    {
                        c.Parameters.AddWithValue("@cid",  companyId);
                        c.Parameters.AddWithValue("@vid",  vehicleId.Value);
                        c.Parameters.AddWithValue("@did",  deviceId);
                        c.Parameters.AddWithValue("@drid", driverId ?? (object)DBNull.Value);
                        c.Parameters.AddWithValue("@msg",  $"Vehicle {body.SpeedMph:F0} mph exceeds {speedThreshold:F0} mph threshold");
                        c.Parameters.AddWithValue("@eid",  eventId);
                    }, ct);
                System.Threading.Interlocked.Increment(ref _alertsGenerated);

                var recommendation = ai.CreateRecommendation(
                    companyId.ToString(CultureInfo.InvariantCulture),
                    "telemetry.speeding",
                    $"Speeding alert for vehicle {vehicleId.Value}",
                    $"Vehicle exceeded telemetry threshold at {body.SpeedMph:F0} mph",
                    0.82m,
                    0.88m,
                    JsonSerializer.Serialize(new { vehicleId, deviceId, alert = "speeding" }),
                    JsonSerializer.Serialize(new { reason = "speed threshold exceeded", threshold = speedThreshold, current = body.SpeedMph }),
                    JsonSerializer.Serialize(new { action = "review_speeding_alert", alertType = "speeding", vehicleId, deviceId }),
                    "medium",
                    eventId.ToString(CultureInfo.InvariantCulture),
                    ActorTypes.ApiKey,
                    deviceId.ToString(CultureInfo.InvariantCulture));

                await db.ExecuteAsync(
                    "UPDATE telemetry_alerts SET ai_recommendation_id=@rid, updated_at=NOW() WHERE id=@id AND company_id=@cid",
                    c =>
                    {
                        c.Parameters.AddWithValue("@rid", recommendation.Id);
                        c.Parameters.AddWithValue("@id", alertId);
                        c.Parameters.AddWithValue("@cid", companyId);
                    }, ct);
            }
        }

        // 17. Alert: geofence breach (best-effort; requires MySQL 5.7.6+, no duplicate open alert per geofence)
        if (vehicleId.HasValue)
        {
            try
            {
                // CIRCLE geofences — great-circle (Haversine) distance in METRES, pure SQL
                // (Postgres has no MySQL ST_Distance_Sphere/POINT). Earth radius 6371000 m.
                // A row is returned when the vehicle is OUTSIDE the circle. Only circle
                // geofences (polygon_json IS NULL); polygons are checked separately below.
                var breached = await db.QuerySingleAsync(
                    @"SELECT g.id, g.name FROM geofences g
                      WHERE g.company_id=@cid AND g.status='Active' AND g.polygon_json IS NULL
                        AND g.center_lat IS NOT NULL AND g.center_lng IS NOT NULL AND g.radius_meters IS NOT NULL
                        AND (2 * 6371000 * ASIN(SQRT(
                              POWER(SIN(RADIANS(@lat - g.center_lat) / 2), 2)
                              + COS(RADIANS(g.center_lat)) * COS(RADIANS(@lat))
                                * POWER(SIN(RADIANS(@lng - g.center_lng) / 2), 2)
                            ))) > g.radius_meters
                      LIMIT 1",
                    c =>
                    {
                        c.Parameters.AddWithValue("@cid", companyId);
                        c.Parameters.AddWithValue("@lat", (double)body.Lat);
                        c.Parameters.AddWithValue("@lng", (double)body.Lng);
                    }, ct);

                // POLYGON geofences — a vehicle OUTSIDE a polygon geofence is a breach.
                // Point-in-polygon (ray casting) is done in C# for correctness/clarity.
                if (breached is null)
                    breached = await FindPolygonBreachAsync(db, companyId, (double)body.Lat, (double)body.Lng, ct);
                if (breached is not null)
                {
                    var gfId   = Convert.ToInt64(breached["id"]);
                    var gfName = breached["name"]?.ToString() ?? "Unknown geofence";
                    var dupGf  = await db.ScalarLongAsync(
                        "SELECT COUNT(*) FROM telemetry_alerts WHERE company_id=@cid AND vehicle_id=@vid AND alert_type='geofence_breach' AND source_event_id=@gid AND status='Open'",
                        c => { c.Parameters.AddWithValue("@cid", companyId); c.Parameters.AddWithValue("@vid", vehicleId.Value); c.Parameters.AddWithValue("@gid", gfId); }, ct);
                    if (dupGf == 0)
                    {
                        var alertId = await db.InsertAsync(
                            @"INSERT INTO telemetry_alerts (company_id, vehicle_id, device_id, alert_type, severity, message, source_event_id, status)
                              VALUES (@cid, @vid, @did, 'geofence_breach', 'High', @msg, @gid, 'Open')
                              RETURNING id",
                            c =>
                            {
                                c.Parameters.AddWithValue("@cid",  companyId);
                                c.Parameters.AddWithValue("@vid",  vehicleId.Value);
                                c.Parameters.AddWithValue("@did",  deviceId);
                                c.Parameters.AddWithValue("@msg",  $"Vehicle outside geofence: {gfName}");
                                c.Parameters.AddWithValue("@gid",  gfId);
                            }, ct);
                        System.Threading.Interlocked.Increment(ref _alertsGenerated);

                        var recommendation = ai.CreateRecommendation(
                            companyId.ToString(CultureInfo.InvariantCulture),
                            "telemetry.geofence_breach",
                            $"Geofence breach near {gfName}",
                            $"Vehicle left the authorized geofence: {gfName}",
                            0.79m,
                            0.92m,
                            JsonSerializer.Serialize(new { vehicleId, deviceId, geofenceId = gfId, geofenceName = gfName }),
                            JsonSerializer.Serialize(new { reason = "outside authorized geofence", geofenceId = gfId, geofenceName = gfName }),
                            JsonSerializer.Serialize(new { action = "review_geofence_breach", geofenceId = gfId, vehicleId, deviceId }),
                            "high",
                            gfId.ToString(CultureInfo.InvariantCulture),
                            ActorTypes.ApiKey,
                            deviceId.ToString(CultureInfo.InvariantCulture));

                        await db.ExecuteAsync(
                            "UPDATE telemetry_alerts SET ai_recommendation_id=@rid, updated_at=NOW() WHERE id=@id AND company_id=@cid",
                            c =>
                            {
                                c.Parameters.AddWithValue("@rid", recommendation.Id);
                                c.Parameters.AddWithValue("@id", alertId);
                                c.Parameters.AddWithValue("@cid", companyId);
                            }, ct);
                    }
                }
            }
            catch { /* ST_Distance_Sphere not available; geofence alerts skipped */ }
        }

        if (vehicleId.HasValue)
        {
            await telemetry.RefreshVehicleAsync(companyId, vehicleId.Value, ct);
        }

        System.Threading.Interlocked.Increment(ref _telemetryAccepted);
        return Results.Ok(ApiResponse<object>.Ok(new { id = eventId, deviceId, companyId }, "Telemetry recorded"));
    }

    // ── GET /api/telemetry/stream (SSE) ─────────────────────────────────────────
    // Auth already validated by Program.cs middleware (SST-only; no session token accepted).
    // Stale-device alerts are generated by TelemetryBackgroundService, not this SSE tick.
    private static async Task TelemetryStream(HttpContext http, Database db, CancellationToken ct)
    {
        // companyId was placed in http.Items by the SST middleware validation
        var companyId = GetCompanyId(http);
        if (companyId <= 0)
        {
            http.Response.StatusCode = 401;
            await http.Response.WriteAsJsonAsync(ApiResponse<object>.Fail("Stream ticket required"));
            return;
        }

        http.Response.Headers.ContentType  = "text/event-stream";
        http.Response.Headers.CacheControl = "no-cache";
        http.Response.Headers.Connection   = "keep-alive";
        http.Response.Headers.Append("X-Accel-Buffering", "no");

        System.Threading.Interlocked.Increment(ref _activeSseClients);

        // Additive provenance, probed ONCE per connection (cached process-wide). When
        // the columns are absent (production pre-migration-001) we select NULL literals
        // so every tick keeps a STABLE shape. `freshness` (live/delayed/stale) is the
        // honest fix-currency label: when provenance columns exist it uses the WORST of
        // receipt-age and device-fix-age (same rule as GET /positions) so a backdated /
        // buffered / replayed frame cannot read 'live'; pre-migration it falls back to
        // received_at only. is_stale (>900s receipt) and every existing field are left
        // untouched. Build the SQL once, reuse it every 3s tick.
        var hasProv = await TelemetryProvenance.ColumnsAvailableAsync(db, ct);
        var provSelect = hasProv
            ? @"lvp.source, lvp.provider, lvp.protocol, lvp.confidence,
                                 lvp.device_fix_time, lvp.gateway_received_at,"
            : @"NULL::text source, NULL::text provider, NULL::text protocol,
                                 NULL::numeric confidence, NULL::timestamptz device_fix_time,
                                 NULL::timestamptz gateway_received_at,";
        var freshAge = hasProv
            ? @"GREATEST(EXTRACT(EPOCH FROM (NOW() - lvp.received_at))::BIGINT,
                                     EXTRACT(EPOCH FROM (NOW() - COALESCE(lvp.device_fix_time, lvp.received_at)))::BIGINT)"
            : "EXTRACT(EPOCH FROM (NOW() - lvp.received_at))::BIGINT";
        var streamSql =
            $@"SELECT lvp.vehicle_id, lvp.device_id, lvp.driver_id,
                                 lvp.lat, lvp.lng, lvp.speed_mph, lvp.heading,
                                 lvp.accuracy_meters, lvp.engine_status,
                                 lvp.fuel_level, lvp.odometer_miles, lvp.event_time,
                                 lvp.received_at, lvp.event_count,
                                 {provSelect}
                                 v.vehicle_code, v.make, v.model, v.status vehicle_status,
                                 d.full_name driver_name,
                                 EXTRACT(EPOCH FROM (NOW() - lvp.received_at))::BIGINT seconds_since_ping,
                                 CASE WHEN EXTRACT(EPOCH FROM (NOW() - lvp.received_at))::BIGINT > 900 THEN 1 ELSE 0 END is_stale,
                                 CASE
                                   WHEN {freshAge} <= 120 THEN 'live'
                                   WHEN {freshAge} <= 900 THEN 'delayed'
                                   ELSE 'stale'
                                 END freshness
                          FROM latest_vehicle_positions lvp
                          LEFT JOIN vehicles v ON v.id=lvp.vehicle_id
                          LEFT JOIN drivers  d ON d.id=lvp.driver_id
                          WHERE lvp.company_id=@cid";

        try
        {
            await http.Response.WriteAsync($"event: connected\ndata: {{\"status\":\"streaming\",\"companyId\":{companyId}}}\n\n", ct);
            await http.Response.Body.FlushAsync(ct);

            while (!ct.IsCancellationRequested)
            {
                try
                {
                    // Per-tick tenant scope: SSE must not hold one request-length transaction
                    // open for the whole connection lifetime. Each 3s read opens a short
                    // tenant scope (RLS filters by company_id), commits, releases. No-op
                    // wrapper (fresh connection per read) when enforcement is off.
                    var positions = await db.RunInTenantScopeAsync(companyId, () => db.QueryAsync(
                        streamSql,
                        c => c.Parameters.AddWithValue("@cid", companyId), ct), ct);

                    var json = System.Text.Json.JsonSerializer.Serialize(positions);
                    await http.Response.WriteAsync($"event: positions\ndata: {json}\n\n", ct);
                    await http.Response.Body.FlushAsync(ct);
                }
                catch (OperationCanceledException) { break; }
                catch { /* DB hiccup — skip tick */ }

                try { await Task.Delay(3000, ct); }
                catch (OperationCanceledException) { break; }
            }
        }
        finally
        {
            System.Threading.Interlocked.Decrement(ref _activeSseClients);
        }
    }

    // ── GET /api/telemetry/positions ─────────────────────────────────────────────
    // REST snapshot using latest_vehicle_positions; scoped to authenticated tenant
    private static async Task<IResult> TelemetryPositions(HttpContext http, Database db, CancellationToken ct)
    {
        var companyId = GetCompanyId(http);
        // Additive provenance: select the source/trust columns only when they
        // exist (deploy-safe — production may pre-date migration 001). Absent →
        // NULL literals so the response keeps a STABLE shape (keys always present,
        // null when unknown). `freshness` is the honest truth-label the map shows: it
        // must reflect the age of the actual GPS FIX, not merely when the pipeline last
        // received a row. When the provenance columns exist we take the WORST (greatest)
        // of receipt-age and device-fix-age (COALESCE to received_at when a fix has no
        // device clock) so a backdated / offline-buffered / replayed frame — which lands
        // with received_at=NOW() but an old device_fix_time — can never read as 'live'.
        // Pre-migration (columns absent) we fall back to received_at only, unchanged.
        // seconds_since_ping and is_stale keep their received_at meaning ("time since we
        // last heard from the device / pipeline"); only the fix-currency label moves.
        var hasProv = await TelemetryProvenance.ColumnsAvailableAsync(db, ct);
        var provSelect = hasProv
            ? @"lvp.source, lvp.provider, lvp.protocol, lvp.confidence,
                     lvp.device_fix_time, lvp.gateway_received_at,"
            : @"NULL::text source, NULL::text provider, NULL::text protocol,
                     NULL::numeric confidence, NULL::timestamptz device_fix_time,
                     NULL::timestamptz gateway_received_at,";
        // Age (seconds) that drives the freshness label. hasProv → max(receipt-age, fix-age).
        var freshAge = hasProv
            ? @"GREATEST(EXTRACT(EPOCH FROM (NOW() - lvp.received_at))::BIGINT,
                         EXTRACT(EPOCH FROM (NOW() - COALESCE(lvp.device_fix_time, lvp.received_at)))::BIGINT)"
            : "EXTRACT(EPOCH FROM (NOW() - lvp.received_at))::BIGINT";

        var positions = await db.QueryAsync(
            $@"SELECT lvp.vehicle_id, lvp.device_id, lvp.driver_id,
                     lvp.lat, lvp.lng, lvp.speed_mph, lvp.heading,
                     lvp.accuracy_meters, lvp.engine_status, lvp.fuel_level,
                     lvp.odometer_miles, lvp.battery_voltage, lvp.event_time,
                     lvp.event_count, lvp.address,
                     {provSelect}
                     v.vehicle_code, v.make, v.model, v.year, v.status vehicle_status,
                     d.full_name driver_name,
                     EXTRACT(EPOCH FROM (NOW() - lvp.received_at))::BIGINT seconds_since_ping,
                     CASE WHEN EXTRACT(EPOCH FROM (NOW() - lvp.received_at))::BIGINT > 900 THEN 1 ELSE 0 END is_stale,
                     CASE
                       WHEN {freshAge} <= 120 THEN 'live'
                       WHEN {freshAge} <= 900 THEN 'delayed'
                       ELSE 'stale'
                     END freshness
              FROM latest_vehicle_positions lvp
              LEFT JOIN vehicles v ON v.id=lvp.vehicle_id
              LEFT JOIN drivers  d ON d.id=lvp.driver_id
              WHERE lvp.company_id=@cid",
            c => c.Parameters.AddWithValue("@cid", companyId), ct);

        return Results.Ok(ApiResponse<object>.Ok(positions, "Positions"));
    }

    // ── GET /api/telemetry/breadcrumbs?vehicleId=&from=&to=&limit= ─────────────────
    // Ordered historical position trail for a vehicle over a time window — powers the
    // live-map "replay" (where did this truck go?). Tenant-scoped; defaults to the last
    // 24h; capped at 1000 points (evenly sampled when the raw trail is larger) so a busy
    // vehicle's replay stays responsive.
    private static async Task<IResult> TelemetryBreadcrumbs(HttpContext http, Database db, CancellationToken ct)
    {
        if (RequirePermission(http, "telemetry.live_state.read") is { } denied) return denied;
        var companyId = GetCompanyId(http);
        if (!long.TryParse(http.Request.Query["vehicleId"].FirstOrDefault(), out var vehicleId) || vehicleId <= 0)
            return Results.BadRequest(ApiResponse<object>.Fail("vehicleId is required"));

        // Time window: explicit from/to (ISO), else last 24h. Cap span at 7 days.
        var toStr = http.Request.Query["to"].FirstOrDefault();
        var fromStr = http.Request.Query["from"].FirstOrDefault();
        var to = DateTime.TryParse(toStr, System.Globalization.CultureInfo.InvariantCulture, System.Globalization.DateTimeStyles.AdjustToUniversal, out var t) ? t : DateTime.UtcNow;
        var from = DateTime.TryParse(fromStr, System.Globalization.CultureInfo.InvariantCulture, System.Globalization.DateTimeStyles.AdjustToUniversal, out var f) ? f : to.AddHours(-24);
        if (to <= from) return Results.BadRequest(ApiResponse<object>.Fail("'to' must be after 'from'"));
        if ((to - from).TotalDays > 7) from = to.AddDays(-7);
        var limit = int.TryParse(http.Request.Query["limit"].FirstOrDefault(), out var l) ? Math.Clamp(l, 2, 2000) : 1000;

        // Even-sample when the raw trail exceeds the limit: row_number() % stride keeps
        // a representative shape without pulling every point.
        var total = await db.ScalarLongAsync(
            @"SELECT COUNT(*) FROM location_events
              WHERE company_id=@cid AND vehicle_id=@vid AND lat IS NOT NULL AND lng IS NOT NULL
                AND event_time BETWEEN @from AND @to",
            c => { c.Parameters.AddWithValue("@cid", companyId); c.Parameters.AddWithValue("@vid", vehicleId);
                   c.Parameters.AddWithValue("@from", from); c.Parameters.AddWithValue("@to", to); }, ct);
        var stride = total > limit ? (int)Math.Ceiling((double)total / limit) : 1;

        var points = await db.QueryAsync(
            @"SELECT lat, lng, speed_mph, heading, engine_status, event_time, source, address
              FROM (
                SELECT lat, lng, speed_mph, heading, engine_status, event_time, source,
                       NULL::text address,
                       ROW_NUMBER() OVER (ORDER BY event_time ASC) rn
                FROM location_events
                WHERE company_id=@cid AND vehicle_id=@vid AND lat IS NOT NULL AND lng IS NOT NULL
                  AND event_time BETWEEN @from AND @to
              ) s
              WHERE (@stride = 1 OR (s.rn - 1) % @stride = 0)
              ORDER BY s.event_time ASC",
            c => { c.Parameters.AddWithValue("@cid", companyId); c.Parameters.AddWithValue("@vid", vehicleId);
                   c.Parameters.AddWithValue("@from", from); c.Parameters.AddWithValue("@to", to);
                   c.Parameters.AddWithValue("@stride", stride); }, ct);

        return Results.Ok(ApiResponse<object>.Ok(new
        {
            vehicleId, from, to,
            totalPoints = total, returnedPoints = points.Count, sampledEvery = stride,
            points,
        }, "Breadcrumbs"));
    }

    // ── POST /api/telemetry/gps-ingest ─────────────────────────────────────────────
    // C2 — normalize a device/forwarder-reported harsh-event token to the canonical alert vocabulary.
    // Accepts the many spellings trackers/forwarders use; returns null for a plain position fix or an
    // unrecognized token (never invents an event).
    private static string? NormalizeHarshEvent(string? raw)
    {
        if (string.IsNullOrWhiteSpace(raw)) return null;
        var v = raw.Trim().ToLowerInvariant().Replace("-", "_").Replace(" ", "_");
        return v switch
        {
            "harsh_braking" or "harshbraking" or "hard_brake" or "harsh_brake" or "braking" or "brake" => "harsh_braking",
            "harsh_acceleration" or "harshacceleration" or "hard_accel" or "harsh_accel" or "acceleration" or "accel" => "harsh_acceleration",
            "harsh_turn" or "harsh_cornering" or "hard_turn" or "cornering" or "turn" or "corner" => "harsh_turn",
            "crash" or "collision" or "accident" or "impact" or "fall" => "crash",
            "sos" or "panic" or "emergency" => "sos",
            _ => null,
        };
    }

    // H3 — provision a per-gateway credential bound to the caller's tenant. Returns the HMAC secret
    // ONCE (never stored in the clear; persisted envelope-encrypted). The gateway then signs gps-ingest
    // with this secret and sends X-Gateway-Id, and may only submit for devices in this tenant.
    private static async Task<IResult> TelemetryGatewayProvision(HttpContext http, Dictionary<string, object?> body, Database db, CancellationToken ct)
    {
        if (RequirePermission(http, "telemetry.devices.manage") is { } denied) return denied;
        var companyId = GetCompanyId(http);
        var gatewayId = (body.TryGetValue("gatewayId", out var g) ? g?.ToString() : null)?.Trim();
        if (string.IsNullOrWhiteSpace(gatewayId))
            return Results.BadRequest(ApiResponse<object>.Fail("gatewayId is required"));
        var name = body.TryGetValue("name", out var n) ? n?.ToString() : null;
        var pii = http.RequestServices.GetRequiredService<Opstrax.Api.Security.PiiProtectionService>();
        // Refuse to mint a gateway secret unless envelope encryption is actually configured — otherwise
        // Encrypt() passes the plaintext through and we would persist a live HMAC secret in the clear.
        if (!pii.Enabled)
            return Results.StatusCode(StatusCodes.Status503ServiceUnavailable);
        var secret = Convert.ToBase64String(System.Security.Cryptography.RandomNumberGenerator.GetBytes(32));
        var encrypted = pii.Encrypt(secret);
        if (string.IsNullOrWhiteSpace(encrypted))
            return Results.StatusCode(StatusCodes.Status503ServiceUnavailable);
        try
        {
            var id = await db.InsertAsync(
                @"INSERT INTO telemetry_gateways (gateway_id, company_id, gateway_name, secret_encrypted, status)
                  VALUES (@g, @c, @n, @s, 'active') RETURNING id",
                c => { c.Parameters.AddWithValue("@g", gatewayId); c.Parameters.AddWithValue("@c", companyId);
                       c.Parameters.AddWithValue("@n", (object?)name ?? DBNull.Value); c.Parameters.AddWithValue("@s", encrypted!); }, ct);
            return Results.Ok(ApiResponse<object>.Ok(new { id, gatewayId, secret }, "Gateway provisioned — copy the secret now, it is shown only once"));
        }
        catch (Npgsql.PostgresException ex) when (ex.SqlState == "23505")
        {
            return Results.Conflict(ApiResponse<object>.Fail("A gateway with that gatewayId already exists"));
        }
    }

    private static async Task<IResult> TelemetryGatewayList(HttpContext http, Database db, CancellationToken ct)
    {
        if (RequirePermission(http, "telemetry.devices.read") is { } denied) return denied;
        var rows = await db.QueryAsync(
            "SELECT id, gateway_id, gateway_name, status, last_seen_at, created_at FROM telemetry_gateways WHERE company_id=@c ORDER BY created_at DESC",
            c => c.Parameters.AddWithValue("@c", GetCompanyId(http)), ct);
        return Results.Ok(ApiResponse<object>.Ok(rows));
    }

    private static async Task<IResult> TelemetryGatewayRevoke(HttpContext http, long id, Database db, CancellationToken ct)
    {
        if (RequirePermission(http, "telemetry.devices.manage") is { } denied) return denied;
        var rows = await db.ExecuteAsync("UPDATE telemetry_gateways SET status='revoked', updated_at=NOW() WHERE id=@id AND company_id=@c",
            c => { c.Parameters.AddWithValue("@id", id); c.Parameters.AddWithValue("@c", GetCompanyId(http)); }, ct);
        if (rows == 0) return Results.NotFound(ApiResponse<object>.Fail("Gateway not found"));
        return Results.Ok(ApiResponse<object>.Ok(new { id, status = "revoked" }, "Gateway revoked"));
    }

    // Trusted-gateway GPS ingest for hardware trackers (GT06/Concox/Jimi PT40-class).
    // The field device talks its vendor protocol to a separately operated gateway; the
    // gateway authenticates here with HMAC. IMEI is only a provisioned lookup key and is
    // never accepted as authentication by itself. Accepts common field aliases and lands the
    // fix on the live map — the same latest_vehicle_positions/location_events tables the
    // map reads. Tolerant of the field-name variety across tracker firmwares/forwarders.
    //
    // Minimal payload: { "imei": "862464068456321", "lat": 34.05, "lng": -118.24 }
    // Aliases accepted: latitude/lng/longitude, speed/speedKmh/speedMph, heading/course/
    // bearing, alt/altitude, ts/timestamp/gpsTime, fuel, odometer.
    private static async Task<IResult> GpsTrackerIngest(HttpContext http, System.Text.Json.JsonElement body, Database db, IConfiguration config, AuditService audit, CancellationToken ct)
    {
        // H3 — per-gateway credentials. If the forwarder identifies itself with X-Gateway-Id, authenticate
        // with THAT gateway's own secret and remember the single tenant it is authorized for (enforced
        // after device resolution below). Absent the header, fall back to the legacy shared fleet secret
        // (dual-run, so already-deployed forwarders like the PT40-Q keep working during migration).
        var gatewayIdHeader = http.Request.Headers["X-Gateway-Id"].FirstOrDefault()?.Trim();
        string? gatewaySecret;
        long? gatewayScopeCompanyId = null;
        var replayGatewayId = GpsGatewayReplayGuard.DefaultGatewayId;
        if (!string.IsNullOrWhiteSpace(gatewayIdHeader))
        {
            var gw = await db.QuerySingleInSystemScopeAsync(
                "SELECT company_id, secret_encrypted, status FROM telemetry_gateways WHERE gateway_id=@g LIMIT 1",
                c => c.Parameters.AddWithValue("@g", gatewayIdHeader), ct);
            if (gw is null || (gw.GetValueOrDefault("status")?.ToString() ?? "") != "active")
                return Results.Unauthorized();
            gatewaySecret = http.RequestServices.GetRequiredService<Opstrax.Api.Security.PiiProtectionService>()
                .Decrypt(gw.GetValueOrDefault("secretEncrypted")?.ToString());
            gatewayScopeCompanyId = Convert.ToInt64(gw["companyId"]);
            replayGatewayId = gatewayIdHeader;
        }
        else
        {
            gatewaySecret = config["Telemetry:GatewaySecret"];
        }
        var timestampRaw = http.Request.Headers["X-Gateway-Timestamp"].FirstOrDefault();
        var signatureRaw = http.Request.Headers["X-Gateway-Signature"].FirstOrDefault();
        if (string.IsNullOrWhiteSpace(gatewaySecret) || gatewaySecret.Length < 32)
            return Results.StatusCode(StatusCodes.Status503ServiceUnavailable);
        if (!long.TryParse(timestampRaw, out var timestamp) || string.IsNullOrWhiteSpace(signatureRaw) ||
            Math.Abs(DateTimeOffset.UtcNow.ToUnixTimeSeconds() - timestamp) > 300)
            return Results.Unauthorized();

        var rawPayload = body.GetRawText();
        if (rawPayload.Length > 32_768) return Results.StatusCode(StatusCodes.Status413PayloadTooLarge);
        using var hmac = new System.Security.Cryptography.HMACSHA256(System.Text.Encoding.UTF8.GetBytes(gatewaySecret));
        var expected = hmac.ComputeHash(System.Text.Encoding.UTF8.GetBytes($"{timestamp}.{rawPayload}"));
        byte[] actual;
        try { actual = Convert.FromHexString(signatureRaw); }
        catch { return Results.Unauthorized(); }
        if (!System.Security.Cryptography.CryptographicOperations.FixedTimeEquals(expected, actual))
            return Results.Unauthorized();

        // Canonical per-message identity for replay defense: the LOWERCASE HEX of the verified
        // HMAC bytes. HMAC decodes hex case-insensitively and compares bytes, so a captured packet
        // re-sent with the signature hex re-cased authenticates as the SAME message — keying on the
        // canonical bytes (not the raw header string) closes that replay bypass. Durable reservation
        // happens after device resolution and inside the write transaction (see below).
        var canonicalSig = Convert.ToHexString(expected).ToLowerInvariant();

        // Header override (X-Device-IMEI) OR body imei/deviceId/id.
        string? Str(params string[] keys)
        {
            foreach (var k in keys)
                if (body.ValueKind == System.Text.Json.JsonValueKind.Object && body.TryGetProperty(k, out var v))
                    return v.ValueKind == System.Text.Json.JsonValueKind.String ? v.GetString() : v.ToString();
            return null;
        }
        double? Num(params string[] keys)
        {
            foreach (var k in keys)
                if (body.ValueKind == System.Text.Json.JsonValueKind.Object && body.TryGetProperty(k, out var v))
                {
                    if (v.ValueKind == System.Text.Json.JsonValueKind.Number && v.TryGetDouble(out var d)) return d;
                    if (v.ValueKind == System.Text.Json.JsonValueKind.String && double.TryParse(v.GetString(), System.Globalization.NumberStyles.Any, System.Globalization.CultureInfo.InvariantCulture, out var ds)) return ds;
                }
            return null;
        }

        var imei = http.Request.Headers["X-Device-IMEI"].FirstOrDefault()?.Trim() ?? Str("imei", "IMEI", "deviceId", "device_id", "id");
        if (string.IsNullOrWhiteSpace(imei))
            return Results.BadRequest(ApiResponse<object>.Fail("imei is required (body 'imei' or header X-Device-IMEI)"));

        var lat = Num("lat", "latitude", "Lat", "Latitude");
        var lng = Num("lng", "lon", "long", "longitude", "Lng", "Longitude");
        if (lat is null || lng is null || !TelemetryTicketHelper.IsCoordinateValid((decimal)lat.Value, (decimal)lng.Value))
            return Results.BadRequest(ApiResponse<object>.Fail("valid lat/lng are required"));

        // Resolve the device by IMEI (or by device_serial == imei, so a serial-registered
        // device also works). Binds company/vehicle from the record — never from the body.
        var device = await db.QuerySingleAsync(
            @"SELECT id, company_id, vehicle_id, driver_id, status
              FROM eld_devices
              WHERE (imei=@imei OR device_serial=@imei) AND deleted_at IS NULL
              LIMIT 1",
            c => c.Parameters.AddWithValue("@imei", imei), ct);
        if (device is null)
            return Results.NotFound(ApiResponse<object>.Fail("Device not found"));
        var devStatus = device.GetValueOrDefault("status")?.ToString() ?? "";
        if (devStatus.Trim().ToLowerInvariant() is not ("active" or "provisioning" or "pending"))
            return Results.Json(ApiResponse<object>.Fail("Device is not enabled for telemetry"), statusCode: 403);

        var deviceId  = Convert.ToInt64(device["id"]);
        var companyId = Convert.ToInt64(device["companyId"]);

        // H3 tenant-scope enforcement: a per-gateway credential may only submit for devices in the tenant
        // it was provisioned for. A gateway asserting another tenant's IMEI is rejected — this is the
        // clause that closes the cross-tenant skeleton key (the legacy shared-secret path has no scope).
        if (gatewayScopeCompanyId is { } scope && scope != companyId)
        {
            // NB: no audit.LogAsync here — this pre-auth gateway path has no tenant in the HTTP context,
            // and AuditService.LogAsync derives the tenant from it (would throw "Missing tenant context").
            // The denial is counted in the rejection metric; a tenant-context-free audit is a follow-up.
            System.Threading.Interlocked.Increment(ref _telemetryRejected);
            return Results.Json(ApiResponse<object>.Fail("Device is not authorized for this gateway"), statusCode: 403);
        }

        long? vehicleId = device["vehicleId"] is null or DBNull ? null : Convert.ToInt64(device["vehicleId"]);
        long? driverId  = device["driverId"]  is null or DBNull ? null : Convert.ToInt64(device["driverId"]);

        // Speed: accept mph directly, or convert km/h. Heading from several aliases.
        var speedMph = Num("speedMph", "speed_mph");
        if (speedMph is null && Num("speedKmh", "speed_kmh", "speed") is { } kmh) speedMph = kmh * 0.621371;
        var heading = Num("heading", "course", "bearing", "direction") ?? 0;
        var engine  = Str("engineStatus", "engine", "ignition") ?? "Running";
        var fuel    = Num("fuel", "fuelLevel", "fuel_level");
        var odo     = Num("odometer", "odometerMiles", "mileage");
        if (speedMph is < 0 or > 250 || heading is < 0 or >= 360 || fuel is < 0 or > 100 || odo is < 0)
            return Results.BadRequest(ApiResponse<object>.Fail("telemetry values are outside accepted bounds"));
        var eventTimeRaw = Str("gpsTime", "gps_time", "eventTime", "event_time", "timestamp", "ts");
        var eventTime = DateTimeOffset.UtcNow;
        if (!string.IsNullOrWhiteSpace(eventTimeRaw))
        {
            if (!TryParseTrackerTimestamp(eventTimeRaw, out eventTime) ||
                eventTime < DateTimeOffset.UtcNow.AddDays(-30) || eventTime > DateTimeOffset.UtcNow.AddMinutes(5))
                return Results.BadRequest(ApiResponse<object>.Fail("device timestamp is invalid or outside the accepted window"));
        }

        // Additive provenance for the trusted-gateway path. Stamp source='gateway'
        // plus the wire protocol/provider the forwarder reported (when present) ONLY
        // when the columns exist (deploy-safe — production may pre-date migration 001).
        // Probed once (cached) BEFORE the system scope so it doesn't nest a probe query
        // inside the write transaction.
        var hasProv = await TelemetryProvenance.ColumnsAvailableAsync(db, ct);
        var provider = Str("provider", "vendor", "manufacturer", "oem");
        var protocol = Str("protocol", "proto");

        // Durable, cross-instance replay defense (TEL-P1-REPLAY-005). The canonical HMAC signature
        // is the per-message identity. Determine the durable store's availability first:
        //   ProbeError -> fail CLOSED (503): a transient DB error must never silently disable replay
        //                 protection by falling through to the process-local path.
        //   Absent     -> pre-migration; reserve in the in-memory fallback here (before any write).
        //   Present    -> reserve durably INSIDE the write transaction below, so a write failure
        //                 rolls the reservation back too (no burned nonce, legitimate retry works).
        var replayAvail = await GpsGatewayReplayGuard.DetermineAvailabilityAsync(db, ct);
        if (replayAvail == GpsGatewayReplayGuard.Availability.ProbeError)
        {
            System.Threading.Interlocked.Increment(ref _telemetryRejected);
            await audit.LogAsync(http, "telemetry.gps.replay_store_unavailable", "EldDevice", deviceId, "fail-closed", ct);
            return Results.StatusCode(StatusCodes.Status503ServiceUnavailable);
        }
        if (replayAvail == GpsGatewayReplayGuard.Availability.Absent &&
            !GpsGatewayReplayGuard.TryReserveInMemory(replayGatewayId, canonicalSig, timestamp))
        {
            System.Threading.Interlocked.Increment(ref _telemetryRejectedReplay);
            System.Threading.Interlocked.Increment(ref _telemetryRejected);
            await audit.LogAsync(http, "telemetry.gps.replay_rejected", "EldDevice", deviceId, "gateway-replay", ct);
            return Results.Conflict(ApiResponse<object>.Fail("Duplicate gateway submission — replay detected"));
        }

        // The durable reserve below runs inside this system-scope transaction, so a write failure
        // rolls the reservation back with it — provided Rls:EnforceTenantContext is ON (the prod
        // invariant this whole handler's write atomicity already depends on). The Absent (in-memory)
        // path can't join the tx, so if the writes throw we compensate by releasing that reservation.
        var durableReplayDuplicate = false;
        try
        {
        await db.RunInSystemScopeAsync(async () =>
        {
            // Durable reservation, atomic with the writes below. A duplicate skips the writes so a
            // replay never lands a row; a DB error here throws and aborts the whole transaction
            // (fail closed — the request 500s, no partial write, reservation rolled back).
            if (replayAvail == GpsGatewayReplayGuard.Availability.Present &&
                !await GpsGatewayReplayGuard.TryReserveDurableAsync(
                    db, replayGatewayId, canonicalSig, timestamp, deviceId, companyId, ct))
            {
                durableReplayDuplicate = true;
                return;
            }

            var eventId = await db.InsertAsync(
                @"INSERT INTO location_events
                    (company_id, vehicle_id, device_id, driver_id, lat, lng, speed_mph, heading,
                     event_type, engine_status, fuel_level, odometer_miles, source, source_channel,
                     event_time, received_at)
                  VALUES (@cid, @vid, @did, @drid, @lat, @lng, @spd, @hdg, 'ping', @eng, @fuel, @odo,
                          'gps-tracker', 'trusted-gateway', @eventTime, NOW())
                  RETURNING id",
                c =>
                {
                    c.Parameters.AddWithValue("@cid", companyId);
                    c.Parameters.AddWithValue("@vid", (object?)vehicleId ?? DBNull.Value);
                    c.Parameters.AddWithValue("@did", deviceId);
                    c.Parameters.AddWithValue("@drid", (object?)driverId ?? DBNull.Value);
                    c.Parameters.AddWithValue("@lat", (decimal)lat.Value);
                    c.Parameters.AddWithValue("@lng", (decimal)lng.Value);
                    c.Parameters.AddWithValue("@spd", (decimal)(speedMph ?? 0));
                    c.Parameters.AddWithValue("@hdg", (short)Math.Clamp((int)heading, 0, 359));
                    c.Parameters.AddWithValue("@eng", engine);
                    c.Parameters.AddWithValue("@fuel", (object?)(fuel is { } fv ? (decimal)fv : (object?)null) ?? DBNull.Value);
                    c.Parameters.AddWithValue("@odo", (object?)(odo is { } ov ? (decimal)ov : (object?)null) ?? DBNull.Value);
                    c.Parameters.AddWithValue("@eventTime", eventTime.UtcDateTime);
                }, ct);

            // C2 — device-reported harsh-driving / crash / SOS event. Normalize the reported token to the
            // canonical alert vocabulary and raise a telemetry_alert linked to this fix; the safety
            // background service converts it into a safety_event (Harsh Braking / Crash / ...) so it lands
            // on the safety dashboard and deducts the driver score. Magnitude (g-force) is kept in the
            // message. Unknown/absent tokens do nothing (a plain position fix is unaffected).
            var harshType = NormalizeHarshEvent(Str("harshEvent", "harsh_event", "event", "alarm", "alarmType"));
            if (harshType is not null)
            {
                var mag = Num("magnitude", "gForce", "g_force", "g", "severityValue");
                var harshSeverity = harshType is "crash" or "sos" ? "Critical" : "High";
                await db.ExecuteAsync(
                    @"INSERT INTO telemetry_alerts
                        (company_id, vehicle_id, device_id, driver_id, alert_type, severity, message, source_event_id, status, source_channel, created_at)
                      VALUES (@cid, @vid, @did, @drid, @type, @sev, @msg, @src, 'open', 'trusted-gateway', NOW())",
                    c =>
                    {
                        c.Parameters.AddWithValue("@cid", companyId);
                        c.Parameters.AddWithValue("@vid", (object?)vehicleId ?? DBNull.Value);
                        c.Parameters.AddWithValue("@did", deviceId);
                        c.Parameters.AddWithValue("@drid", (object?)driverId ?? DBNull.Value);
                        c.Parameters.AddWithValue("@type", harshType);
                        c.Parameters.AddWithValue("@sev", harshSeverity);
                        c.Parameters.AddWithValue("@msg", mag is { } m ? $"Device-reported {harshType} (magnitude {m:0.##})" : $"Device-reported {harshType}");
                        c.Parameters.AddWithValue("@src", eventId);
                    }, ct);
            }

            if (vehicleId is not null)
            {
                var provCols = hasProv ? ", source, provider, protocol, device_fix_time, gateway_received_at, normalized_at" : "";
                var provVals = hasProv ? $", '{TelemetryProvenance.SourceGateway}', @provider, @protocol, @eventTime, NOW(), NOW()" : "";
                var provUpd  = hasProv
                    ? $", source='{TelemetryProvenance.SourceGateway}', provider=EXCLUDED.provider, protocol=EXCLUDED.protocol, device_fix_time=EXCLUDED.device_fix_time, gateway_received_at=EXCLUDED.gateway_received_at, normalized_at=NOW()"
                    : "";

                await db.ExecuteAsync(
                    $@"INSERT INTO latest_vehicle_positions
                        (company_id, vehicle_id, device_id, driver_id, lat, lng, speed_mph, heading,
                         engine_status, fuel_level, odometer_miles, event_time, received_at, event_count,
                         source_event_id, source_channel, telemetry_status, risk_level, updated_at{provCols})
                      VALUES (@cid, @vid, @did, @drid, @lat, @lng, @spd, @hdg, @eng, @fuel, @odo, @eventTime, NOW(), 1,
                              @eid, 'trusted-gateway', 'healthy', 'low', NOW(){provVals})
                      ON CONFLICT (company_id, vehicle_id) DO UPDATE SET
                        device_id=EXCLUDED.device_id, lat=EXCLUDED.lat, lng=EXCLUDED.lng,
                        speed_mph=EXCLUDED.speed_mph, heading=EXCLUDED.heading,
                        engine_status=EXCLUDED.engine_status, fuel_level=EXCLUDED.fuel_level,
                        odometer_miles=EXCLUDED.odometer_miles, event_time=EXCLUDED.event_time, received_at=NOW(),
                        event_count=latest_vehicle_positions.event_count+1, source_event_id=EXCLUDED.source_event_id,
                        source_channel='trusted-gateway', telemetry_status='healthy', risk_level='low', updated_at=NOW(){provUpd}
                      WHERE latest_vehicle_positions.event_time IS NULL OR latest_vehicle_positions.event_time <= EXCLUDED.event_time",
                    c =>
                    {
                        c.Parameters.AddWithValue("@cid", companyId);
                        c.Parameters.AddWithValue("@vid", vehicleId.Value);
                        c.Parameters.AddWithValue("@did", deviceId);
                        c.Parameters.AddWithValue("@drid", (object?)driverId ?? DBNull.Value);
                        c.Parameters.AddWithValue("@lat", (decimal)lat.Value);
                        c.Parameters.AddWithValue("@lng", (decimal)lng.Value);
                        c.Parameters.AddWithValue("@spd", (decimal)(speedMph ?? 0));
                        c.Parameters.AddWithValue("@hdg", (short)Math.Clamp((int)heading, 0, 359));
                        c.Parameters.AddWithValue("@eng", engine);
                        c.Parameters.AddWithValue("@fuel", (object?)(fuel is { } fv ? (decimal)fv : (object?)null) ?? DBNull.Value);
                        c.Parameters.AddWithValue("@odo", (object?)(odo is { } ov ? (decimal)ov : (object?)null) ?? DBNull.Value);
                        c.Parameters.AddWithValue("@eid", eventId);
                        c.Parameters.AddWithValue("@eventTime", eventTime.UtcDateTime);
                        if (hasProv)
                        {
                            c.Parameters.AddWithValue("@provider", (object?)provider ?? DBNull.Value);
                            c.Parameters.AddWithValue("@protocol", (object?)protocol ?? DBNull.Value);
                        }
                    }, ct);
            }

            // A valid signed fix is the activation proof. Never activate suspended or
            // revoked devices (rejected above); only advance the explicit provisioning state.
            await db.ExecuteAsync(
                @"UPDATE eld_devices
                  SET last_seen_at=NOW(), last_heartbeat_at=NOW(),
                      status=CASE WHEN LOWER(status) IN ('provisioning','pending') THEN 'Active' ELSE status END
                  WHERE id=@id",
                c => c.Parameters.AddWithValue("@id", deviceId), ct);
        }, ct);
        }
        catch
        {
            // Writes failed. The durable reservation (Present path) rolled back with the tx; the
            // in-memory fallback (Absent path) did not, so release it here to keep a legitimate
            // retry from being rejected as a replay.
            if (replayAvail == GpsGatewayReplayGuard.Availability.Absent)
                GpsGatewayReplayGuard.ReleaseInMemory(replayGatewayId, canonicalSig);
            throw;
        }

        // The durable reservation ran inside the transaction and found this signature already
        // present: the transaction committed no fix (writes were skipped). Reject as a replay.
        if (durableReplayDuplicate)
        {
            System.Threading.Interlocked.Increment(ref _telemetryRejectedReplay);
            System.Threading.Interlocked.Increment(ref _telemetryRejected);
            await audit.LogAsync(http, "telemetry.gps.replay_rejected", "EldDevice", deviceId, "gateway-replay", ct);
            return Results.Conflict(ApiResponse<object>.Fail("Duplicate gateway submission — replay detected"));
        }

        return Results.Ok(ApiResponse<object>.Ok(new
        {
            accepted = true,
            mapped = vehicleId is not null,
            eventTime = eventTime.ToString("O")
        }, "GPS fix recorded"));
    }

    internal static bool TryParseTrackerTimestamp(string raw, out DateTimeOffset value)
    {
        value = default;
        if (long.TryParse(raw, NumberStyles.Integer, CultureInfo.InvariantCulture, out var epoch))
        {
            try
            {
                value = Math.Abs(epoch) >= 100_000_000_000L
                    ? DateTimeOffset.FromUnixTimeMilliseconds(epoch)
                    : DateTimeOffset.FromUnixTimeSeconds(epoch);
                return true;
            }
            catch (ArgumentOutOfRangeException) { return false; }
        }

        return DateTimeOffset.TryParse(raw, CultureInfo.InvariantCulture,
            DateTimeStyles.AssumeUniversal | DateTimeStyles.AdjustToUniversal, out value);
    }

    // ── GET /api/telemetry/metrics ────────────────────────────────────────────────
    private static IResult TelemetryMetrics(HttpContext http)
    {
        var denied = RequirePermission(http, "telemetry.live_state.read");
        if (denied is not null) return denied;
        return Results.Ok(ApiResponse<object>.Ok(new
        {
            accepted           = System.Threading.Interlocked.Read(ref _telemetryAccepted),
            rejected           = System.Threading.Interlocked.Read(ref _telemetryRejected),
            authFailed         = System.Threading.Interlocked.Read(ref _telemetryAuthFailed),
            rejectedReplay     = System.Threading.Interlocked.Read(ref _telemetryRejectedReplay),
            rejectedValidation = System.Threading.Interlocked.Read(ref _telemetryRejectedValidation),
            activeSseClients   = System.Threading.Interlocked.Read(ref _activeSseClients),
            alertsGenerated    = System.Threading.Interlocked.Read(ref _alertsGenerated),
            asOf               = DateTime.UtcNow
        }, "Telemetry metrics"));
    }

