              FROM fault_codes fc
              LEFT JOIN vehicles v ON v.id=fc.vehicle_id
              WHERE fc.company_id=@cid AND fc.status=@status
              ORDER BY ARRAY_POSITION(ARRAY['Critical','Warning','Info'], fc.severity), fc.last_seen_at DESC
              LIMIT 100",
